window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]=window.__LIBQ["pham-nhan-tu-tien"]["q06"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q06"]["characters"]={"updatedAt":"2026-07-15","count":52,"chars":[{"id":"nho-sinh-cam-bao","name":"Nho sinh cẩm bào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Kết Đan","trangThai":"song","blurb":"Tu sĩ nam khoảng bốn mươi tuổi, đại ca của nhóm ba người. Có sinh tử chi giao với người Quỷ Linh Môn, bỏ mười vạn linh thạch mua ba Trụy Ma Lệnh bài để nhập Trụy Ma Cốc tìm bảo vật.","vaiTro":"Đại ca nhóm ba tu sĩ mua Trụy Ma Lệnh bài nhập cốc","tinhCach":"Quả quyết, dám chi tiền lớn; có mưu lược và quan hệ rộng; biết trấn an đồng bạn","tabs":{"diem":[{"text":"Bỏ gần hết gia sản mười vạn linh thạch mua ba Trụy Ma Lệnh bài nhờ quan hệ sinh tử chi giao với người Quỷ Linh Môn.","chuong":"@c0793"}],"kinhLich":[{"chuong":"@c0793","importance":"normal","mucCt":"vua","tieuDe":"Mua Trụy Ma Lệnh bài nhập cốc","text":"Nhờ sinh tử chi giao với người Quỷ Linh Môn, bỏ mười vạn linh thạch mua ba Trụy Ma Lệnh bài. Trấn an hai sư đệ về rủi ro khe hở không gian, cả ba quyết định nhập Trụy Ma Cốc chỉ dò xét vùng ngoài.","anchor":"cuối cùng cũng kịp lúc và lệnh bài cũng về tới tay ta"}],"tuViMoc":[],"tuVi":"Kết Đan kỳ (chưa ngưng kết Nguyên Anh, mục tiêu tìm linh đan trong cốc để đột phá).","nhanMach":[{"ten":"Nam tu sĩ áo lam","tag":"dong-hanh","quanHe":"Nhị đệ, đồng hành nhập Trụy Ma Cốc"},{"ten":"Nữ tu sĩ cung trang","tag":"dong-hanh","quanHe":"Đồng hành nhập Trụy Ma Cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Trụy Ma Lệnh","moTa":"Ba tấm lệnh bài thanh đồng, mua từ Quỷ Linh Môn với giá mười vạn linh thạch.","trangThai":"dang-co","nguon":"@c0793"}]}},"nguon":["@c0793"]},{"id":"nam-tu-ao-lam","name":"Nam tu sĩ áo lam","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Kết Đan","trangThai":"song","blurb":"Tu sĩ nam khoảng ba mươi tuổi, nho nhã tuấn tú, nhị đệ trong nhóm ba người. Lo lắng tiếc nuối mười vạn linh thạch nhưng cuối cùng đồng ý theo đại ca nhập Trụy Ma Cốc.","vaiTro":"Nhị đệ trong nhóm ba tu sĩ nhập Trụy Ma Cốc","tinhCach":"Thận trọng, hay lo lắng; trung thành với đại ca","tabs":{"diem":[{"text":"Lo ngại rủi ro khe hở không gian và nghi ngờ phương pháp nhập cốc của Quỷ Linh Môn, nhưng cuối cùng vẫn theo đại ca.","chuong":"@c0793"}],"kinhLich":[{"chuong":"@c0793","importance":"bridge","mucCt":"gon","text":"Cùng đại ca và nữ tu sĩ bàn bạc rủi ro rồi quyết định nhập Trụy Ma Cốc.","anchor":"Một khi đại ca đã nói như vậy thì bọn tiểu đệ sẽ cùng với huynh nhập cốc"}],"tuViMoc":[],"tuVi":"Kết Đan kỳ.","nhanMach":[{"ten":"Nho sinh cẩm bào","tag":"dong-hanh","quanHe":"Đại ca, người dẫn dắt nhóm"},{"ten":"Nữ tu sĩ cung trang","tag":"dong-hanh","quanHe":"Đồng hành nhập Trụy Ma Cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0793"]},{"id":"nu-tu-cung-trang","name":"Nữ tu sĩ cung trang","cn":"","aliases":[],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Kết Đan","trangThai":"song","blurb":"Nữ tu sĩ dáng đầy đặn gương mặt bình thường, thành viên nhóm ba người. Hưng phấn kỳ vọng tìm thượng cổ linh đan trong Trụy Ma Cốc để ngưng kết Nguyên Anh.","vaiTro":"Thành viên nhóm ba tu sĩ nhập Trụy Ma Cốc","tinhCach":"Quả quyết, hưng phấn trước cơ hội; không muốn bỏ lỡ","tabs":{"diem":[{"text":"Kỳ vọng tìm thượng cổ linh đan diệu dược trong Trụy Ma Cốc để ba người ngưng kết Nguyên Anh.","chuong":"@c0793"}],"kinhLich":[{"chuong":"@c0793","importance":"bridge","mucCt":"gon","text":"Hưng phấn khi có Trụy Ma Lệnh bài, quả quyết cùng hai đồng bạn nhập cốc tìm linh đan.","anchor":"Nếu có thể tìm được một ít thượng cổ linh đan diệu dược thì ba người chúng ta có thể ngưng kết nguyên anh được rồi"}],"tuViMoc":[],"tuVi":"Kết Đan kỳ.","nhanMach":[{"ten":"Nho sinh cẩm bào","tag":"dong-hanh","quanHe":"Đại ca, người dẫn dắt nhóm"},{"ten":"Nam tu sĩ áo lam","tag":"dong-hanh","quanHe":"Đồng hành nhập Trụy Ma Cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0793"]},{"id":"han-lap","name":"Hàn Lập","cn":"韩立","gioiTinh":"nam","tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c0794","tieuDe":"Trở về Thiên Nam, hội ngộ tại Diệp Hoa","text":"Hàn Lập trở về Thiên Nam sau hơn hai năm đi tới chỗ cực tây, xuất hiện tại khách điếm Hồng Phúc ở thành Diệp Hoa. Tinh thần và khí chất biến hóa rõ rệt, trầm ổn thâm sâu khó lường hơn trước. Mang theo ống trúc vàng bí ẩn dài khoảng một trượng sau lưng, không thu vào túi trữ vật. Nói ở cực tây gặp phiền toái nhỏ đã giải quyết nhưng bị chậm trễ thời gian. Xác nhận giữ lời hứa cùng Tử Linh đi vào Trụy Ma Cốc, trong khi Mai Ngưng và nữ tử họ Tống quyết định không đi vì hung hiểm quá lớn.","anchor":"Thì ra vị nam tử này đây chính là Hàn Lập người mà hai năm trước đây đã đi tới chổ cực tây đã trở về."},{"importance":"normal","mucCt":"ky","chuong":"@c0795","tieuDe":"Lộ diện Đại Diễn Thần Quân trong ống trúc","text":"Xác nhận thông tin Linh Chúc Quả qua ngọc giản của trưởng lão Quỷ Linh Môn, thảo luận kế hoạch nhập Trụy Ma Cốc với Tử Linh và thống nhất luyện Tạo Hóa Đan ngay trong cốc. Dùng truyền âm thuật bàn kế hoạch bí mật với Tử Linh. Vội vã rời đi vì bị Đại Diễn Thần Quân quấy nhiễu tâm tư từ bên trong ống trúc. Lộ ra Đại Diễn Thần Quân chính là linh hồn cổ đại trú trong Thiên Lôi Trúc, từng dùng Thất Tình Quyết khống chế cảm xúc hỉ nộ ái ố của hắn thông qua đệ nhị nguyên anh nhưng không khống chế được thần thức. Không tiêu diệt lão vì cần ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi đại uy lực, đồng thời sưu hồn thuật vô hiệu trước thần thức cường đại của lão.","anchor":"Đối mặt với Đại diễn Thần Quân, một lão quái vật đã sống trên một ngàn năm mà nói Hàn Lập không có cách nào xuống tay được."},{"importance":"normal","mucCt":"ky","chuong":"@c0796","tieuDe":"Hồi tưởng giao dịch với Đại Diễn Thần Quân","text":"Hàn Lập đối thoại với Đại Diễn Thần Quân, hồi tưởng lại chuyện năm xưa phát hiện lão trong mật thất Thiên Trúc Giáo. Khi lão dùng Thất Tình Quyết tập kích khiến nguyên anh thứ hai cuồng tính đại phát, Hàn Lập phản kích bằng Đồng Hóa Thuật qua nguyên anh chủ, đe dọa tinh hồn lão cùng nguyên anh thứ hai đồng quy vu tận, tạo thế giằng co. Cho lão mượn Dưỡng Hồn Mộc đổi lấy ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật. Từ chối lời đề nghị bái sư vì đã tu nhiều loại công pháp, không cải tu lại. Đánh giá lão là kỳ tài ngàn năm có một.","anchor":"Nói hắn là kỳ tài ngàn năm có một còn có chút xem nhẹ"},{"importance":"normal","mucCt":"ky","chuong":"@c0797","tieuDe":"Nhận tầng 5 Đại Diễn Quyết và bí sử Ma Giới","text":"Hỏi Đại Diễn Thần Quân về phong hồn chú, được xác nhận lão có năng lực nhưng thọ nguyên không đủ thời gian để phá giải. Quyết chí phải đi Trụy Ma Cốc tìm bảo vật giải chú. Nghe Thần Quân tiết lộ bí sử Thượng Cổ Ma Giới, cuộc chiến thượng cổ tu sĩ với cổ ma, nguồn gốc ma công từ Cổ ma giới, và nguy hiểm khe hở không gian trong cốc. Nhận ngọc giản chứa khẩu quyết tầng thứ năm Đại Diễn Quyết cùng hai phương pháp luyện chế và kết đan Khôi Lỗi từ Thần Quân — là phần thù lao đã hứa. Nhớ lại Mộ Lan pháp sĩ dùng cổ đăng triệu hoán yêu cầm, liên hệ với cổ ma. Biết ống trúc sau lưng (động phúc thiên kỳ) là bảo vật không gian chứa chân thân Khôi Lỗi của Thần Quân. Ra ngoài thành kiểm tra sinh vật bí ẩn tóc xanh mắt bích lục bị chôn trong đất, xác nhận đã bồi dưỡng được thần thức đơn giản, hài lòng cho rằng có thể phát huy tại Trụy Ma Cốc. Thiết lập cấm chế phụ cận, khoanh chân tọa hạ. Cuối cùng lấy ra lệnh bài vàng khắc ba chữ Thiên Cực Môn, mắt nheo phát tinh quang suy tư.","anchor":"Nhìn trên mặt lệnh bài này có khắc nổi ba chữ \" Thiên Cực Môn \""},{"mucCt":"ky","text":"Thu hồi Thiên tuyệt ma thi rồi lên đường tới Vạn Linh Sơn, chưa tìm được Nam Lũng Hầu nhưng tự tin hắn sẽ chủ động tìm đến nhờ Lưỡng nghi hoàn. Suy đoán Bắc Cực hoang nguyên là thông đạo bên trong Trụy Ma Cốc chứ không phải lối vào. Dự định luyện chế Khôi Lỗi cấp Kết Đan kỳ, vẫn thiếu tài liệu Huyết phượng mộc cho Khôi Lỗi thượng cổ cấp Nguyên Anh, đã phân phó đệ tử Lạc Vân Tông tìm kiếm. Phát hiện trận đấu pháp, nhận ra tiêu ký hình chiếc lá vàng của Hoàng Phong Cốc trên cổ tay nho sinh, dừng lại can thiệp buộc hai tu sĩ Ngự Linh Tông thu quân rút lui. Gặp Trần Xảo Thiên — anh trai Trần Xảo Thiến, biết tin Trần Xảo Thiến không phải Kết Đan tu sĩ, đã mắc quái bệnh qua đời hơn trăm năm trước, trong lòng bi ai nhớ lại hình ảnh người xưa và lần cuối nàng thổ lộ tiếng lòng.","anchor":"Trong đầu không khỏi hiện lên hình ảnh Trần Xảo Thiến xinh đẹp như hoa, cũng nhớ tới tràng cảnh nữ nhân này lần cuối cùng cùng mình du sơn đã thổ lộ tiếng lòng","bridge":true,"khoang":"@c0798"},{"mucCt":"ky","text":"Nghe Trần Xảo Thiên kể Trần Xảo Thiến độc thân đến cuối đời, mắt hiện dị sắc, đè nén nỗi thương nhớ. Cảnh báo ba người về Trụy Ma Cốc chánh ma tề tụ rồi hóa thanh hồng bay đi. Bay đến Vạn Linh Sơn, dùng thần thức ngang Nguyên Anh Hậu Kỳ quét phương viên hơn trăm dặm. Hỏi đường lão giả Trúc Cơ, mua tài liệu luyện khí tại phường thị mới mở. Dùng hơn mười khẩu phi kiếm khai mở động phủ tạm trong tiểu sơn, bố trí hai pháp trận che mắt. Thả Ngân Nguyệt tự tu luyện, Thiên tuyệt ma thi nhập thổ trong mật thất. Nghiên cứu ngọc giản Đại diễn Thần Quân ba ngày ba đêm, nắm rõ hai loại Khôi Lỗi Kết Đan Kỳ (hình cự quy phòng ngự + hình hổ yêu cận chiến), quyết định luyện chế cả hai loại, bắt đầu luyện chế.","anchor":"Nhất thời thần thức cường đại có thể so sánh với tu sĩ Nguyên Anh Hậu Kỳ bắt đầu bao phủ phạm vi phương viên hơn trăm dặm nhanh chóng tìm kiếm","bridge":true,"khoang":"@c0799"},{"mucCt":"ky","text":"Bế quan mấy tháng trong mật thất, luyện chế thành hơn ba mươi khối Khôi Lỗi gồm Quy hình và Hổ yêu, mỗi loại chiếm một nửa, nhờ đại lượng yêu hồn cấp cao lấy từ Loạn Tinh Hải. Kiểm tra Thiên tuyệt ma thi thấy bình thường, thu hồi. Thu thân yêu hồ Ngân Nguyệt vào tay áo rồi rời động phủ. Ngồi trên đỉnh núi buông thần thức quét phương viên trăm dặm tìm người nhưng không thấy, thần thức cường đại đến mức lão quái Nguyên Anh Sơ Kỳ cũng không nhận ra. Đến phường thị phát hiện Bạch Thư Quân, ném Thiên cực lệnh xác nhận thân phận, yêu cầu dẫn đường gặp Lỗ Vệ Anh. Được Lỗ Vệ Anh vui mừng đón tiếp, vào chỗ ở bí mật nói chuyện riêng.","anchor":"Hàn Lập trước sau đã luyện chế thành hơn ba mươi khối Khôi Lỗi Quy hình cùng Khôi lỗ hình thái Hổ yêu, mỗi thứ chiếm một nửa","bridge":true,"khoang":"@c0800"},{"mucCt":"ky","text":"Đến động phủ Lỗ trưởng lão gặp Nam Lũng Hầu và Lỗ Vệ Anh, khiêm tốn nói chiến tích giết tu sĩ Nguyên Anh Trung Kỳ Ma Tông Tần quốc chỉ nhờ may mắn. Đàm phán phân chia bảo vật, đồng ý chia đều ba phần nhưng yêu cầu nội đan Hỏa Thiềm cổ thú phải thuộc về mình. Chính thức đồng ý nhập Trụy Ma Cốc cùng hai người, nhấn mạnh ba người phải toàn lực hợp tác mới còn mạng trở ra.","anchor":"Vậy nội đan của Hỏa Thiềm cổ thú kia, phải lưu lại cho tại hạ","bridge":true,"khoang":"@c0801"},{"mucCt":"ky","text":"Đến phụ cận Trụy Ma Cốc, cách lối vào hơn mười dặm, cảm nhận hơn ngàn tu sĩ tụ tập gồm cả lão quái Nguyên Anh. Thử dùng thần thức dò cốc khẩu nhưng chỉ xâm nhập được hơn trăm trượng thì bị cấm chế ngăn cản, cẩn thận thu hồi rồi ngồi nhập định chờ đợi. Nửa ngày sau quan sát đoàn Mộ Lan pháp sĩ đến bằng phi xa hình nón, nhận ra Trọng Thần Sư và Nhạc thượng sư dẫn đầu. Thấy Quỷ Linh Môn hơn trăm tu sĩ xuất hiện, nhận ra Vương Thiên Cổ, Vương Thiền tay chân dường bình thường, Yến Như Yên thần sắc tiều tụy. Suy đoán Âm Ma Trảm trước đó chưa gây trọng thương Vương Thiền hoặc tay chân đã nối lại. Tự đánh giá ngoài tam đại tu sĩ và Mộ Lan thần sư thì sơ sẩy vẫn có thể mất mạng. Đặc biệt chú ý lão giả lạ mặt Nguyên Anh Trung Kỳ bên Quỷ Linh Môn.","anchor":"Hàn Lập cũng không có tự phụ, trừ tam đại tu sĩ và Mộ Lan thần sư ra, sơ sẩy một tí, cũng sẽ để cái mạng nhỏ tại chỗ này","bridge":true,"khoang":"@c0802"},{"mucCt":"ky","text":"Quan sát Quỷ Linh Môn thiết trí pháp trận lớn tại cốc khẩu Trụy Ma Cốc, nhận ra nó giống thượng cổ Truyền Tống Trận đã bị cải biến. Kinh ngạc khi Ngụy Vô Nhai xuất hiện hợp tác cùng Quỷ Linh Môn, tự đánh giá nếu xung đột hắn chỉ có cách chạy trối chết. Chứng kiến Vương Thiên Cổ lấy ra linh thạch bậc cao kim hoàng sắc đặt vào trung tâm pháp trận, nhận thấy vật cực hiếm gần tuyệt tích Thiên Nam mà hắn đánh chết nhiều tu sĩ vẫn chưa từng thấy. Nghe tông chủ Quỷ Linh Môn Vương Thiên Thắng tuyên bố quy tắc nhập cốc qua Đan Hướng Truyền Tống Trận.","anchor":"hắn cũng chỉ có cách chạy trối chết. Đây chính là chuyện lớn nhất ngoài suy đoán của hắn","bridge":true,"khoang":"@c0803"},{"mucCt":"ky","text":"Đứng trên cao quan sát các tu sĩ lần lượt truyền tống vào Trụy Ma Cốc. Đệ nhị Nguyên Anh (Mộc Linh Anh đồng hóa 7-8 phần) bất an kịch liệt suýt xuất khiếu khi Ngũ Hành Linh Anh tới gần, Hàn Lập dùng thần thức trấn trụ. Nhận ra năm tu sĩ lục bào theo Đông Môn Đồ chính là Ngũ Hành Linh Anh, đồng thời biết Đông Môn Đồ đã phát hiện Linh Anh trên mình và liếc với ý bất thiện. Từ chối lời khuyên lui của Ngụy Vô Nhai, khẳng định có đạo lý nhất định phải vào Trụy Ma Cốc. Bị Vương Thiên Thắng nhận ra danh tính và kiêng kỵ. Được truyền tống tới sườn núi đổ nát trong cốc, xung quanh đồi núi thấp, cỏ dại cao nửa người, không một bóng người, xoay đầu nhìn thấy điều gì đó ngạc nhiên.","anchor":"đệ nhị Nguyên anh đã đồng hóa được bảy tám phần của Hàn Lập đột nhiên kịch liệt bất an","bridge":true,"khoang":"@c0804"},{"mucCt":"ky","text":"Được truyền tống vào ngoại cốc Trụy Ma Cốc, phát hiện hố tròn trăm trượng do thần thông thượng cổ tạo thành, dùng phong thuật thổi sạch bụi lộ thạch bích dung nham đỏ sậm. Bắn Phệ Kim Trùng lên không trung thử nghiệm cấm chế thiên không, xác nhận bay quá năm sáu mươi trượng sẽ bị lam sắc thiểm điện đánh, nhưng Phệ Kim Trùng thân thể kiên cố chịu được sét rồi hồi phục. Khai thần thức toàn bộ kèm Minh Thanh Linh Nhãn bay chậm về phía tây, phát hiện khe hở không gian hữu hình hình trăng non cỡ một trượng, thử bắn kiếm khí vào bị nuốt mất, bay vòng tránh. Xác lập thứ tự ưu tiên: hội hợp Nam Lũng Hầu ở phía tây cốc diệt hỏa thiềm thú lấy nội đan cho Nam Cung Uyển trước, sau đó mới tìm linh chúc quả, đồng thời hứng thú với bảo vật trên di hài thượng cổ tu sĩ do hỏa thiềm cổ thú trông coi.","anchor":"Hàn Lập một bên tự đánh giá một bên không ngừng xoay đầu trông chừng xung quanh","bridge":true,"khoang":"@c0805"},{"mucCt":"ky","text":"Bay đến nơi hẹn với thanh hồng độn quang, mang áo choàng xanh khiến thần thức không xuyên thấu được, gây kinh ngạc cho Nam Lũng Hầu và Lỗ Vệ Anh. Cùng hai người thương lượng kế sách diệt hỏa thiềm thú rồi lên đường bay hơn nửa ngày đến gần nội cốc. Dùng linh nhãn phát hiện khe hở không gian ẩn hình mà cảm ứng linh của Nam Lũng Hầu không cảnh báo được, nhưng giữ bí mật không tiết lộ. Suy đoán nội cốc có thể từng là lao tù hoặc lồng giam. Chứng kiến Nam Lũng Hầu dùng ngọc bội trắng phá huyễn thuật, mở lối vào thông đạo bí mật dẫn vào nội cốc.","anchor":"dùng linh nhãn nhìn thấy một khe hở không gian ẩn hình cách ba người một bên không xa","bridge":true,"khoang":"@c0807"},{"chuong":"@c0808","importance":"normal","mucCt":"ky","tieuDe":"Thông đạo nội cốc — phát hiện gián điệp, bày trận","text":"Cùng Nam Lũng Hầu và Lỗ Vệ Anh đến thông đạo sương mù dẫn vào nội cốc Trụy Ma Cốc. Dùng linh nhãn thần thông quan sát sương mù, phát hiện chỗ bất thường mà hai người kia không thấy. Phát hiện Hoàng Thiên Minh dùng thượng cổ ẩn hình phù ẩn nặc theo dõi, bắn kiếm khí ép hắn hiện hình. Đề nghị bố trận che giấu động tĩnh trước khi diệt cự mãng, dùng trận kỳ trong suốt bày pháp trận phạm vi lớn đè nén tiếng vang và linh khí ba động.","anchor":"Hàn mỗ cũng không có ý kiến. Bất quá trước khi tiến hành việc này chúng ta hay là nên trước hết mời một vị đạo hữu khác đi ra đã"},{"mucCt":"ky","text":"Phóng Kinh Long chung tấn công cự mãng nhưng bị lục quang hộ thể chặn, sau đó cự mãng kéo dài thân nuốt gọn Kinh Long chung vào bụng. Thả sáu con Khôi Lỗi thú (ba bạch lang, hai hồng ngưu, một thanh mãng) từ giao dịch với Thiên Tinh Chân Nhân lần đầu ra trận thực chiến. Bị cự mãng hút gió tạo hấp lực khổng lồ, dùng thanh quang tăng trọng lượng cơ thể chống lại. Điều khiển hồng ngưu bắn xích mang vào họng mãng gây đau, bạch lang tấn công đầu mãng nhưng không phá nổi lân phiến. Cự mãng lộ chân tướng Tam Thủ Ô Xà với hai đầu phụ nuốt hai bạch lang, Hàn Lập lạnh lùng ra lệnh kích nổ hai Khôi Lỗi trong miệng xà đầu phụ.","anchor":"Hàn Lập mặt lộ ra một tia hoảng sợ, nhưng trong lòng vẫn bình tĩnh","bridge":true,"khoang":"@c0809"},{"mucCt":"ky","text":"Kích hoạt hai bạch lang Khôi Lỗi tự bạo trong miệng cự mãng gây thương tích hai đầu bên. Tung cổ bảo Thiên Trọng Phong hóa hắc sắc sơn phong cao hơn mười trượng, phun hắc hà ngưng trệ cự mãng rồi nện xuống nghiền nát phần lớn thân. Thu hồi Khôi Lỗi thú còn lại và trận kỳ xung quanh, nhận một viên thanh sắc nội đan. Nhận định cự mãng là xà thú biến dị chứ không phải tam thủ ô xà chính thức vì thiếu nhục sí và ba đầu không có thần thông bất đồng thuộc tính. Dẫn đầu đoàn bay thêm hai mươi dặm tới thạch bích có sơn động dẫn vào nội cốc.","anchor":"Hàn Lập trầm giọng nói sau đó dẫn đầu bước đi","bridge":true,"khoang":"@c0810"},{"mucCt":"ky","text":"Phát hiện mỏ Cương Ngân Sa trong thạch bích Trụy Ma Cốc, dùng phi kiếm xác nhận cả tòa thạch bích chứa quặng mật độ không đều. Nghe Đại Diễn Thần Quân truyền pháp quyết điều khiển Phệ Kim Trùng cắn nuốt khoáng vật trong đá, bí mật phóng thích toàn bộ Phệ Kim Trùng vào thạch bích khai thác mà hai đồng hành không hay biết. Tiết lộ pháp bảo phi kiếm đã dùng Luyện Tinh luyện chế nên không cần Cương Ngân Sa, cũng không còn Luyện Tinh thừa. Khi ba người tiến sâu gặp Bắc Cực Nguyên Quang chặn đường, lấy ra chiếc nhẫn đen Lưỡng Nghi hoàn chuẩn bị vượt qua.","anchor":"một đám kim sắc Phệ Kim Trùng vô thanh vô tức từ trong tay áo bay ra","bridge":true,"khoang":"@c0811"},{"mucCt":"ky","text":"Kích hoạt Lưỡng Nghi hoàn bằng thanh khí, chiếc nhẫn phóng to thành cự hoàn đường kính năm sáu trượng, phát hào quang bảo hộ màu đen. Ném viên châu phòng hộ linh khí thử nghiệm uy lực Bắc Cực Nguyên Quang, viên châu bị ngân ti xuyên thủng nổ tung. Xác nhận Lưỡng Nghi hoàn bẻ cong được ngân ti, che chắn ba người an toàn vượt qua vùng Bắc Cực Nguyên Quang.","anchor":"Hàn Lập tay cầm Lưỡng Nghi hoàn, hé miệng phun ra một đoàn thanh khí lên trên chiếc nhẫn","bridge":true,"khoang":"@c0812"},{"mucCt":"ky","text":"Cùng Nam Lũng Hầu và Lỗ Vệ Anh bước qua động khẩu trên vách núi cao ngàn trượng, chính thức tiến vào nội cốc Trụy Ma Cốc. Dùng linh nhãn phát hiện khe hở không gian vô hình cách trăm trượng, cảnh báo hai người đồng hành. Phi hành theo lộ tuyến quanh co do Nam Lũng Hầu dẫn đường, âm thầm ghi nhớ toàn bộ đường đi làm đường rút lui. Dùng nhất tâm nhị dụng vừa ghi nhớ vừa cảm ứng xung quanh, phát hiện 3-4 chỗ có cấm chế thượng cổ phát ra ba động mãnh liệt nhưng đè nén lòng tham, từ bỏ ý định mạo hiểm. Đánh giá cổ bảo bình thường đã không còn giá trị, xác định mục tiêu chính là yêu đan Hỏa Thiềm thú, bảo vật bên hài cốt cổ tu sĩ, Linh Chúc quả và Cương Ngân Sa. Quan sát Lỗ Vệ Anh sắc mặt âm trầm hay nhìn về phía xa, cảm thông với áp lực thọ mệnh của lão.","anchor":"hắn càng nghiên cứu về thượng cổ kỳ trận thì càng kiêng kỵ đối với loại cấm chế kia","bridge":true,"khoang":"@c0813"},{"mucCt":"ky","text":"Phân tích hai con đường nguy hiểm dẫn đến sào huyệt Hỏa Thiềm thú: đường trái có hơn mười con Phi Thiên Tử Vân hạt, đường phải có khe hở không gian vô hình. Dù có Linh nhãn thần thông nhìn thấy khe hở không gian nhưng kiên quyết giấu bí mật lớn nhất này, chọn đối mặt với Tử Vân hạt. Nhận ra bình Bích Cưu (một trong Thập Tuyệt độc) trong hộp bảo vật Thương Khôn Thượng Nhân, đề xuất dùng mùi cay của Bích Cưu bôi lên khôi lỗi để dẫn dụ phi hạt rời đi. Triệu bốn năm cự viên khôi lỗi mang bình độc dịch bay lên đỉnh núi trái thực hiện kế hoạch. Nghi ngờ Nam Lũng Hầu cố tình giấu thông tin về Tử Vân hạt đến phút cuối nhằm đào hố, bất mãn vì bị đổ hết việc nhưng nhẫn nhịn. Hồi tưởng tượng yêu thú ba đầu sáu tay trong di chỉ Thương Khôn, mơ hồ cảm giác có huyền cơ ẩn bên trong. Quyết tâm lấy xong yêu đan Hỏa Thiềm thú sẽ lập tức chia tay hai đồng hành.","anchor":"Đây là chỗ dựa lớn nhất của hắn ở trong Trụy Ma Cốc","bridge":true,"khoang":"@c0814"},{"mucCt":"ky","text":"Dùng Khôi Lỗi cự viên làm mồi nhử dẫn dụ đàn Tử Vân hạt rời đỉnh núi, bị công kích âm thanh tác động trực tiếp chân nguyên suýt rơi từ không trung nhưng nhờ tu vi cao hơn tu sĩ cùng cấp nên vượt qua mà không cần dùng Phong Lôi Sí. Không giải thích nguồn gốc Bích Cưu độc là di vật Thương Khôn Thượng Nhân khi bị hỏi. Dùng thần thức dò xét động khẩu Hỏa Thiềm thú nhưng không dám dò sâu sợ kinh động. Bố trí thêm mấy loại pháp trận bên ngoài đại trận Thủy thuộc tính của Nam Lũng Hầu để phòng bất trắc. Cuối cùng khoanh chân ngồi bên pháp trận, thao túng Khôi Lỗi hình bạch lang cuối cùng bay về phía sơn động dẫn dụ Hỏa Thiềm thú.","anchor":"thao túng con khôi lỗi thú này bay thẳng về phía sơn động nọ","bridge":true,"khoang":"@c0815"},{"importance":"normal","chuong":"@c0815","tieuDe":"Vượt ải Tử Vân hạt, định kế săn Hỏa Thiềm thú","mucCt":"ky","text":"Thả vài con khôi lỗi cự viên tẩm Bích Cưu độc làm mồi dụ đàn Tử Vân hạt mười ba, mười bốn con rời tổ. Trúng âm công bén nhọn của đàn hạt khiến khí huyết quay cuồng, suýt rơi khỏi không trung. Nhận định loại âm công này đánh thẳng tới chân nguyên chứ không tác động thần thức, hiểu rằng điển tịch ghi về Thập Tuyệt độc không đầy đủ. Cùng hai đồng bạn giải ẩn nặc phá không vượt đỉnh núi, không cần dùng Phong Lôi Sí nhờ tu vi vượt xa tu sĩ cùng cấp. Cảm ứng đám khôi lỗi cự viên dần mất liên lạc, coi như tổn thất toàn bộ. Khi được khen công, chỉ hàm hồ đáp cho qua, giấu việc Bích Cưu độc là bảo vật Thương Khôn Thượng Nhân để lại. Tới Dung Nham Chi Địa, dò thần thức thấy động khẩu đỏ lớn của sào huyệt Hỏa Thiềm thú rồi vội thu lại vì sợ kinh động con thú. Bố trí thêm mấy loại pháp trận phụ bên cạnh đại trận Thủy thuộc tính của Nam Lũng Hầu. Cuối chương ngồi cạnh pháp trận, thao túng con khôi lỗi hình bạch lang còn sót lại bay về phía sơn động dụ thú ra ngoài.","anchor":"Lần này tất cả là nhờ vào Bích Cưu độc cùng khôi lỗi của Hàn huynh"},{"chuong":"@c0816","importance":"normal","mucCt":"ky","tieuDe":"Dụ phục Hỏa Thiềm Thú vào pháp trận","text":"Phái khôi lỗi bạch lang thăm dò hang Hỏa Thiềm Thú, phát hiện hồ dung nham với thú ngủ giữa hồ và di hài cổ tu sĩ trên thạch thai mặc trường bào xanh cổ xưa. Thần thức bị trường bào cổ phóng linh quang chặn lại, đánh thức Hỏa Thiềm Thú. Khôi lỗi bạch lang bị yêu hỏa thiêu hủy hoàn toàn, nhận ra yêu hỏa mạnh hơn anh hỏa Nguyên Anh Kỳ. Chủ động hiện thân triệu sáu khôi lỗi cự quy mới luyện, dùng băng diễm đối đầu thử uy lực. Giả vờ thua chạy dẫn dụ Hỏa Thiềm Thú lọt pháp trận, phối hợp Nam Lũng Hầu và Lỗ Vệ Anh cùng thủy long vây đánh. Hỏa Thiềm Thú thi triển thần thông bảo mệnh tạo vòng bảo vệ ba tầng, phóng quang trụ xuyên thủng thủy mạc pháp trận.","anchor":"Sinh tử của Nam Cung Uyển liên quan đến cổ thú kia nên hắn làm sao để cho nó dễ dàng thoát đi"},{"mucCt":"ky","text":"Khi Hỏa Thiềm thú sắp phá pháp trận thoát ra ngoài, Hàn Lập kịp thời dùng Âm Ma trảm từ xa chém đứt chân trước yêu thú, ngăn nó trốn thoát. Điều khiển sáu khôi lỗi phun quang trụ lam đè ép yêu thú xuống mặt đất. Triển khai hơn mười thanh Thanh Trúc Phong Vân kiếm hợp nhất thành cự kiếm, phủ Cực Hàn lam diễm kết hợp kích phát Ích Tà Thần Lôi lên thân kiếm. Nhận ra hỏa đạn yêu thú phun ra không phải yêu đan thật, dùng điện võng phá giải quang xà cầm cố kiếm. Cự kiếm phá mười lớp quang thuẫn liên tiếp, chém đứt lưỡi yêu thú cứng như pháp bảo nhờ kiếm đã thêm Canh Tinh, rồi trảm đầu Hỏa Thiềm thú. Sau đó cảnh giác ngăn Nam Lũng Hầu triệt pháp trận, nhận ra yêu thú chưa chết hẳn vì linh quang vẫn phiêu phù không rơi.","anchor":"Hỏa Thiềm thú vẫn chưa tiêu diệt hoàn toàn. Nam Lũng huynh không cần quá khẩn trương như vậy.","bridge":true,"khoang":"@c0817"},{"mucCt":"ky","text":"Dùng cự kiếm phân hai đạo kim quang kết hợp băng diễm đông kết Hỏa Thiềm thú có Bất diệt chi thể thành tượng băng rồi phá hủy hoàn toàn, thu yêu đan đỏ rực — đạt một trong các mục đích vào Trụy Ma Cốc. Hai thanh phi kiếm phân giải thành hơn mười thanh tiểu kiếm thu về tay áo. Đánh giá dù Nam Lũng Hầu và Lỗ Vệ Anh liên thủ thì xác suất thắng cũng chỉ 5:5, đề cao cảnh giác phòng bị. Từ bỏ ý định lén phái Ngân Nguyệt vào động vì sợ bị phát hiện. Cùng hai người vào sào huyệt Hỏa Thiềm thú, xem xét di hài cổ tu sĩ trên thạch thai bên hồ dung nham. Khi Nam Lũng Hầu thu Thanh Tàm bào thì thần sắc khẽ biến rồi nhanh chóng khôi phục. Kiểm tra túi trữ vật cổ tu sĩ, phát hiện linh liệu, nhiều cổ bảo, hộp ngọc trắng và hai dược bình đen không thể dùng thần thức tra xét.","anchor":"trong lòng đã sớm tăng cao cảnh giác đối với hai người kia để đề phòng bọn họ thấy lợi mờ mắt","bridge":true,"khoang":"@c0818"},{"mucCt":"ky","text":"Hàn Lập cùng Nam Lũng Hầu và Lỗ Vệ Anh bàn cách phân chia ba kiện bảo vật thu được. Giả vờ đòi lấy hai viên cổ linh đan để ép Nam Lũng Hầu và Lỗ Vệ Anh nhượng bộ, vì cả hai đều sắp hết thọ nguyên nên rất cần linh đan. Cuối cùng miễn cưỡng đồng ý bỏ linh đan, chỉ lấy chiếc cổ kính tím, ngọc giản luyện chế Thất Diễm phiến và linh liệu, viện cớ hứng thú luyện khí chi đạo. Thực chất ngọc giản chính là phương pháp luyện chế Thông Thiên Linh Bảo mà Nam Lũng Hầu và Lỗ Vệ Anh không biết giá trị thật. Ngân Nguyệt và Đại Diễn Thần Quân bí mật thông báo Thất Diễm phiến là Thông Thiên Linh Bảo, Hàn Lập dẹp tranh cãi giữa hai người rồi quyết tâm lấy ngọc giản.","anchor":"Tại hạ có chút hứng thú đối với luyện khí chi đạo","bridge":true,"khoang":"@c0819"},{"importance":"normal","mucCt":"ky","chuong":"@c0820","tieuDe":"Nhường bảo vật, thu Thanh Tàm bào, phát hiện địa đồ bí mật","text":"Nhường hai kiện cổ bảo cho Nam Lũng Hầu và Lỗ Vệ Anh, đổi lấy linh thạch tương đương. Tùy tiện thu lấy Thanh Tàm bào mà Nam Lũng Hầu vứt bỏ. Cáo từ hai người, chọn xuất cốc theo đường cũ vì ưu tiên tìm Linh Chúc quả. Trên đường phi hành, xé góc Thanh Tàm bào phát hiện bên trong giấu mảnh vải vẽ sơ đồ Trụy Ma Cốc có tiêu ký thô to bắt mắt.","anchor":"Ha ha…việc này chỉ trách hai lão gia hỏa kia có mắt không tròng mà thôi!"},{"mucCt":"ky","text":"Hàn Lập xem bản đồ Trụy Ma Cốc, nhận thấy khoảng cách tới mục tiêu còn rất xa, quyết ưu tiên tìm Linh Chúc Quả trước. Hắn dùng kích tướng pháp thách Đại Diễn Thần Quân nghiên cứu phương pháp thay thế vật liệu luyện chế Thông Thiên Linh Bảo Thất Diễm Phiến, đổi lại sẽ đáp ứng một điều kiện của lão. Nội tâm tiết lộ hắn đã sở hữu Hư Thiên Đỉnh nhưng chưa biết cách mở ra, và muốn có thêm Thông Thiên Linh Bảo.","anchor":"Trong tay hắn mặc dù đã có Thông thiên linh bảo Hư Thiên Đỉnh. Nhưng vẫn còn không biết cách mở ra","bridge":true,"khoang":"@c0821"}],"nhanMach":[{"ten":"Đại Diễn Thần Quân","tag":"khac","quanHe":"Linh hồn trú trong ống trúc, hứa truyền ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi cho Hàn Lập","ghiChu":"Từng dùng Thất Tình Quyết tấn công Hàn Lập nhưng thất bại vì đệ nhị nguyên anh"},{"ten":"Trần Xảo Thiên","tag":"khac","quanHe":"Anh trai Trần Xảo Thiến, đệ tử Hoàng Phong Cốc, được Hàn Lập cứu giúp","ghiChu":"@c0798"},{"ten":"Nữ tu họ Viên","tag":"khac","quanHe":"Nữ tu đi cùng Bạch Thư Quân, gặp thoáng qua tại phường thị.","ghiChu":"@c0800"},{"ten":"Nữ tử họ Lỗ","tag":"khac","quanHe":"Hậu nhân của Lỗ Vệ Anh, gặp khi đến chỗ ở Lỗ Vệ Anh.","ghiChu":"@c0800"},{"ten":"Tu sĩ hắc bào rộng (Quỷ Linh Môn)","tag":"doi-thu","quanHe":"Tu sĩ Nguyên Anh lạ mặt của Quỷ Linh Môn, Hàn Lập chú ý quan sát"},{"ten":"Lão giả mắt chim ưng (Quỷ Linh Môn)","tag":"doi-thu","quanHe":"Tu sĩ Nguyên Anh Trung Kỳ lạ mặt của Quỷ Linh Môn, Hàn Lập đặc biệt để mắt"}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ống trúc vàng","moTa":"Dài khoảng một trượng, màu vàng, mang sau lưng không thu vào túi trữ vật, không rõ bên trong chứa gì","trangThai":"dang-co","nguon":"@c0794"}]}},"nguon":["@c0794","@c0795","@c0796","@c0797","@c0798","@c0799","@c0800","@c0801","@c0802","@c0803","@c0804","@c0805","@c0806","@c0807","@c0808","@c0809","@c0810","@c0811","@c0812","@c0813","@c0814","@c0815","@c0816","@c0817","@c0818","@c0819","@c0820","@c0821"],"canhGioiCaoNhat":"Kết Đan Hậu Kỳ","trangThai":"song"},{"id":"tu-linh-tien-tu","name":"Tử Linh Tiên Tử","cn":"紫灵仙子","aliases":["Tử Linh"],"gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c0794","tieuDe":"Chờ Hàn Lập tại Diệp Hoa, bàn kế nhập cốc","text":"Thi triển bí thuật ẩn nặc dung mạo, cùng Mai Ngưng và nữ tử họ Tống chờ Hàn Lập tại khách điếm Hồng Phúc. Thừa nhận nếu Hàn Lập không đến thì một mình không dám vào Trụy Ma Cốc. Phủ nhận việc cố ý tung tin về Trụy Ma Cốc cho Quỷ Linh Môn, cho rằng tu sĩ vào cốc càng ít càng tốt để ra tay trước lấy Linh Chúc Quả.","anchor":"Ta chỉ là một người Kết Đan Sơ Kỳ mà độc thân đi vào chắc chắn chỉ có một con đường là chết mà thôi."},{"mucCt":"ky","text":"Khẳng định tin tưởng Hàn Lập mười phần, đưa ngọc giản chứng minh Linh Chúc Quả có thật. Cho biết đã chuẩn bị hơn mười mấy phần phụ liệu luyện Tạo Hóa Đan. Chấp nhận điều kiện mỗi người tự bảo vệ nếu gặp nguy hiểm quá lớn, thể hiện tính cách cương liệt. Xác nhận nhập cốc cần mượn lực đệ tử Quỷ Linh Môn. Bị Đại Diễn Thần Quân nhận ra dung mạo thật rất xinh đẹp dù thi triển bí thuật che giấu.","anchor":"mặc dù thi triển bí thuật che dấu đi dung nhan thật đi. Nhưng làm sao có thể che dấu được thần thức của lão phu","bridge":true,"khoang":"@c0795"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0794","@c0795","@c0806"]},{"id":"mai-ngung","name":"Mai Ngưng","cn":"妙凝","gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c0794","tieuDe":"Từ chối nhập Trụy Ma Cốc","text":"Cương quyết không vào Trụy Ma Cốc vì chỉ là Kết Đan Sơ Kỳ, tự biết khả năng bản thân, đã có một lọ linh dược trợ giúp kết đan nên không cần mạo hiểm. Trong lòng phiền muộn vì trước đây do dự không chọn Hàn Lập, bây giờ danh tiếng Hàn Lập lớn nên không dễ mở miệng nữa.","anchor":"Bây giờ Hàn Lập có danh tiếng lớn như thế. Cho nên nàng không dễ mở miệng ra nữa."},{"importance":"bridge","mucCt":"gon","chuong":"@c0795","tieuDe":"","text":"Có mặt trong buổi gặp với Hàn Lập, lộ vẻ thất vọng khi Hàn Lập vội vã rời đi.","anchor":"Hàn Lập tiếp nhận ngọc giản, đem thần thức đắm chìm vào trong đó yên lặng xem"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Lọ linh dược trợ kết đan","moTa":"Linh dược trợ giúp việc kết đan, Mai Ngưng đã có trước đó","trangThai":"dang-co","nguon":"@c0794"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0794","@c0795"]},{"id":"tong-mong","name":"Nữ tử họ Tống","aliases":["Tống sư điệt"],"gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c0794","tieuDe":"Bàn luận uy danh Hàn Lập, từ chối nhập cốc","text":"Ngày càng cung kính Hàn Lập sau khi biết chiến tích giết tu sĩ Nguyên Anh Trung Kỳ. Quyết định không vào Trụy Ma Cốc vì hung hiểm quá lớn. Đề cập Quỷ Linh Môn đột nhiên thừa nhận tin tức về Trụy Ma Cốc, nghi Tử Linh cố ý tiết lộ.","anchor":"Hiện tại Hàn sư thúc bây giờ ở Thiên Nam cũng chỉ thấp hơn tam đại tu sĩ mà thôi."},{"importance":"bridge","mucCt":"gon","chuong":"@c0795","tieuDe":"","text":"Trình bày thông tin cho Hàn Lập, cho biết không rõ vị trí Trình sư huynh vì ông đi cùng bạn cũ.","anchor":"Trình sư huynh nghĩ tới đại nạn sắp tới nên cũng đã nhập cốc rồi"}],"nhanMach":[],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0794","@c0795"]},{"id":"dai-dien-than-quan","name":"Đại Diễn Thần Quân","cn":"大衍神君","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Trúc Giáo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh Hậu Kỳ","trangThai":"song","blurb":"Linh hồn cổ đại trú trong ống trúc dưới dạng khôi lỗi, là người khai sáng và lập ra Thiên Trúc Giáo năm xưa, đã tồn tại hơn một ngàn năm. Tinh hồn nhiều nhất còn hơn mười năm rồi tan.","vaiTro":"Linh hồn cổ đại trú trong ống trúc của Hàn Lập, hứa truyền thụ ba tầng cuối Đại Diễn Quyết","tinhCach":"Lão luyện trầm trồ; thích trêu chọc Hàn Lập; chán nản vì tồn tại hơn ngàn năm không có cảm giác","tabs":{"diem":[{"text":"Khai sáng Thiên Trúc Giáo năm xưa, tồn tại dưới dạng khôi lỗi hơn ngàn năm, tinh hồn sắp tan trong hơn mười năm nữa","chuong":"@c0795"},{"text":"Từng dùng Thất Tình Quyết tấn công Hàn Lập nhưng thất bại vì đệ nhị nguyên anh, hiện hứa truyền ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi đại uy lực","chuong":"@c0795"},{"text":"Thần thức cường đại khó tin, sưu hồn thuật hoàn toàn vô hiệu với lão","chuong":"@c0795"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c0795","tieuDe":"Lộ diện trong ống trúc của Hàn Lập","text":"Linh hồn cổ đại trú trong ống trúc (Thiên Lôi Trúc), bị Hàn Lập vạch trần thân phận là Đại Diễn Thần Quân — người khai sáng Thiên Trúc Giáo. Từng thi triển Thất Tình Quyết nhằm khống chế chủ nguyên thần Hàn Lập nhưng thất bại vì đệ nhị nguyên anh. Hiện tồn tại dưới dạng khôi lỗi, tinh hồn nhiều nhất còn hơn mười năm. Hứa truyền thụ ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi đại uy lực cho Hàn Lập. Khiến tâm tư Hàn Lập xao động khi cố ý khuấy động cảm xúc qua Thất Tình Quyết. Tự thú nhận chưa nghiên cứu hoàn thành, mới chế được hơn phân nửa khôi lỗi.","anchor":"ngươi lại là Đại Diễn Thần Quân khai sáng và lập ra Thiên Trúc Giáo năm đó"},{"importance":"normal","mucCt":"ky","chuong":"@c0796","tieuDe":"Tiết lộ toàn bộ lai lịch và sáng lập Ký Thần Thuật","text":"Kể lại quá khứ: năm xưa tự phụ tài trí hơn người, phân tâm sáng tạo Đại Diễn Quyết, sáng lập Thiên Trúc Giáo, nghiên cứu Khôi Lỗi Thuật thất truyền, tu đến Nguyên Anh Hậu Kỳ. Đánh bại hai tu sĩ Chánh Ma đệ nhất Thiên Nam, bức họ phát thệ vạn năm nhường Cực Tây, sở hữu hơn ngàn Khôi Lỗi. Nhận ra sai lầm trí mạng khi thọ nguyên cạn mà không thể đột phá Hóa Thần do phân tâm quá nhiều. Dùng hai trăm năm cuối sáng lập Ký Thần Thuật lấy Đại Diễn Quyết làm trụ cột nhưng chỉ hoàn thành một nửa, bất đắc dĩ sử dụng, buông bỏ tu vi, thần thức nhập Khôi Lỗi đặc chế, bị nhốt vạn năm trong mật thất. Được Hàn Lập cứu nhờ Dưỡng Hồn Mộc, đổi lại truyền ba tầng sau Đại Diễn Quyết và Khôi Lỗi Thuật. Muốn thu Hàn Lập làm đệ tử nhưng bị từ chối. Giải thích ba tầng sau không truyền đệ tử vì không ai đạt Nguyên Anh, truyền chỉ chuốc họa.","anchor":"tự phụ tài trí hơn người, trong thiên hạ không ai sánh bằng, cho nên phân tâm làm nhiều chuyện"},{"importance":"normal","mucCt":"ky","chuong":"@c0797","tieuDe":"Giao tầng 5 Đại Diễn Quyết và tiết lộ bí sử Ma Giới","text":"Khẳng định có khả năng phá phong hồn chú nhưng thọ nguyên có hạn không đủ thời gian. Cảnh báo Hàn Lập về Trụy Ma Cốc: thượng cổ cấm chế, khe hở không gian bất ngờ có thể thông tới Thượng Cổ Ma Giới. Tiết lộ bí sử thượng cổ về cuộc chiến tu sĩ và cổ ma khiến thượng cổ tu sĩ suy tàn, nhiều công pháp và linh thú diệt tuyệt. Giải thích ma đạo tu sĩ tu luyện thượng cổ ma công vốn là đường lối tu luyện của Cổ ma còn sót lại. Kể về bạn hữu năm xưa liên thủ vào Trụy Ma Cốc gặp cổ ma khóa giới, chỉ một người phân thần thoát. Giao ngọc giản chứa khẩu quyết tầng 5 Đại Diễn Quyết cùng hai phương pháp luyện chế và kết đan Khôi Lỗi cho Hàn Lập, gọi đây là thù lao đã hứa. Tuyên bố cần dưỡng tinh thần nghiên cứu Khôi Lỗi Thuật, không muốn bị quấy rầy.","anchor":"Tiếp theo, lão phu phải dưỡng tinh thần, tiếp tục nghiên cứu Khôi Lỗi Thuật"},{"chuong":"@c0800","importance":"bridge","mucCt":"vua","text":"Đang ở trong Động phúc thiên nghiên cứu Khôi Lỗi Thuật, thấy Hàn Lập liên tục lấy ra yêu hồn cấp cao thì kinh ngạc gọi Tiểu quái vật rồi im lặng.","anchor":"cảm thấy kinh ngạc kêu lên một tiếng \" Tiểu quái vật\" rồi lập tức im lặng"},{"mucCt":"ky","text":"Hưng phấn khi phát hiện Cương Ngân Sa, muốn dùng trộn vào thân khôi lỗi mới khiến pháp bảo thường không thể tổn thương. Truyền cho Hàn Lập pháp quyết cổ văn điều khiển Phệ Kim Trùng chui vào thạch bích cắn nuốt khoáng vật rồi nhả tinh thể ngưng kết — pháp quyết này năm xưa lão đoạt từ một tu sĩ bị lão đánh chết. Đặt điều kiện Cương Ngân Sa ưu tiên luyện khôi lỗi, còn thừa mới cho Hàn Lập tùy ý. Kích động khi nghe Hàn Lập có Luyện Tinh, thất vọng khi biết không còn thừa.","anchor":"Dùng nó trộn lẫn vào thân thể khôi lỗi thì bảo vật bình thường không có cách nào làm tổn thương chúng","bridge":true,"khoang":"@c0811"},{"importance":"bridge","mucCt":"vua","chuong":"@c0819","tieuDe":"Hưng phấn trước Thông Thiên Linh Bảo","text":"Hưng phấn khi biết có phương pháp luyện chế Thông Thiên Linh Bảo, nói từ lâu muốn nghiên cứu. Bị Ngân Nguyệt chất vấn về chuyện cũ (đề xuất mượn Ngân Nguyệt nghiên cứu vì chưa từng thấy khí linh có linh trí), tự bào chữa rồi đành im.","anchor":"Lão phu sớm đã muốn nghiên cứu Thông Thiên Linh Bảo"},{"mucCt":"ky","text":"Đại Diễn Thần Quân tiết lộ năm xưa từ cổ tu di chỉ tìm được ít tư liệu về Thông Thiên Linh Bảo, nghiên cứu nhiều năm không có thu hoạch. Lão tự thừa nhận chỉ còn mười năm nữa là hồn phi phách tán. Dù biết Hàn Lập dùng kích tướng pháp, lão vẫn chấp nhận nghiên cứu tài liệu thay thế cho Thất Diễm Phiến, đổi lấy một yêu cầu trong tương lai.","anchor":"Lão phu sau nhiều năm nghiên cứu, cũng có lưu ý đến loại bảo vật này, chỉ đáng tiếc tin tức liên quan đến Thông thiên linh bảo thực sự quá ít","bridge":true,"khoang":"@c0821"}],"tuViMoc":[{"chuong":"@c0796","canhGioi":"Nguyên Anh Hậu Kỳ","text":"Xác nhận tu vi cao nhất đạt được là Nguyên Anh Hậu Kỳ, tự nhận nếu không phân tâm thì tiến Hóa Thần không khó. Sau khi dùng Ký Thần Thuật chưa hoàn chỉnh, buông bỏ đại bộ phận tu vi, chỉ còn thần thức trong Khôi Lỗi đặc chế.","importance":"major"}],"nhanMach":[{"ten":"Hàn Lập","tag":"khac","quanHe":"Người giữ ống trúc chứa tinh hồn, sẽ được truyền ba tầng cuối Đại Diễn Quyết và phương pháp luyện chế khôi lỗi","ghiChu":"Từng dùng Thất Tình Quyết tấn công Hàn Lập nhưng thất bại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0795","@c0796","@c0797","@c0800","@c0811","@c0819","@c0821"]},{"id":"hac-bao-phap-si-thu-linh-mo-lan","name":"Hắc bào pháp sĩ thủ lĩnh Mộ Lan","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0797","bridge":true,"khoang":"@c0797–@c0797","text":"Bị Hàn Lập nhắc lại việc dùng cổ đăng triệu hoán yêu cầm, liên hệ với cổ ma đến qua khe hở không gian.","anchor":"nhớ tới Mộ Lan pháp sĩ dùng cổ đăng gọi về một đầu yêu cầm"}]},"nguon":["@c0797"]},{"id":"tran-xao-thien","name":"Trần Xảo Thiên","cn":"陈巧倩","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Phong Cốc","trangThai":"gan-bo"},{"ten":"Trần thị gia tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kết Đan Kỳ","trangThai":"song","vaiTro":"Anh trai Trần Xảo Thiến, đệ tử Hoàng Phong Cốc, người báo tin Trần Xảo Thiến qua đời","tinhCach":"Lễ phép, cảm kích ơn cứu mạng","blurb":"Nho sinh trung niên, đệ tử Hoàng Phong Cốc thuộc Trần thị gia tộc, tu vi Kết Đan trung kỳ. Là anh trai Trần Xảo Thiến, người cho Hàn Lập biết tin Trần Xảo Thiến đã qua đời hơn trăm năm trước vì quái bệnh.","tabs":{"diem":[{"text":"Anh trai Trần Xảo Thiến, mang tiêu ký hình chiếc lá vàng của Hoàng Phong Cốc","chuong":"@c0798"},{"text":"Đệ tử Hoàng Phong Cốc, đại ca nhóm ba kết nghĩa, nhận ra Hàn Lập qua dung mạo trẻ trung và lời đồn trong tông môn","chuong":"@c0799"},{"text":"Vừa luyện chế xong pháp bảo tổ truyền Kim Thư ngân bút từ pháp khí phỏng chế, chuẩn bị cho Trụy Ma Cốc","chuong":"@c0799"}],"kinhLich":[{"mucCt":"ky","text":"Cầm đầu nhóm ba người (cùng hai huynh muội kết nghĩa Hóa Đao Ổ) bị hai tu sĩ Ngự Linh Tông khu sử cự đại phi nga tấn công, bị ép hạ phong. Được Hàn Lập nhận ra tiêu ký Hoàng Phong Cốc trên cổ tay mà can thiệp cứu giúp. Tự giới thiệu là đệ tử Hoàng Phong Cốc, cho Hàn Lập biết Trần Xảo Thiến là gia muội của mình, không phải Kết Đan tu sĩ, đã mắc quái bệnh qua đời hơn trăm năm trước.","anchor":"Gia muội cũng không phải là Kết Đan Tu Sĩ. Từ hơn trăm năm trước gặp phải một hồi quái bệnh đã qua đời rồi.","bridge":true,"khoang":"@c0798"},{"mucCt":"vua","text":"Kể cho Hàn Lập chuyện tiểu muội Trần Xảo Thiến bị hủy hôn vì bên kia ngả phe ma đạo, sau đó trầm mặc ít nói, độc thân đến cuối đời. Nhận ra thân phận Hàn Lập, tiết lộ cho hai nghĩa đệ muội lai lịch Hàn Lập: xuất thân Hoàng Phong Cốc, phá Mộ Lan thánh cầm, trảm ma tu trưởng lão, địa vị chỉ dưới Thiên Nam tam đại tu sĩ. Vừa luyện chế xong Kim Thư ngân bút pháp bảo từ pháp khí tổ truyền, khuyên cả nhóm cẩn thận tại Trụy Ma Cốc.","anchor":"Ngày xưa xuất thân từ Hoàng Phong Cốc chúng ta, ngày nay lại từng từ trong tay Mộ Lan thần sư toàn vẹn thoát đi","bridge":true,"khoang":"@c0799"}],"tuViMoc":[{"chuong":"@c0798","canhGioi":"Kết Đan trung kỳ","text":"Tu vi Kết Đan trung kỳ khi gặp Hàn Lập","importance":"minor"}],"nhanMach":[{"ten":"Trần Xảo Thiến","tag":"ho-hang","quanHe":"Gia muội, đã qua đời hơn trăm năm trước vì quái bệnh","ghiChu":"@c0798"},{"ten":"Hàn Lập","tag":"an-nhan","quanHe":"Ân nhân cứu mạng, Nguyên Anh tu sĩ Lạc Vân Tông, có quen biết cũ với Hoàng Phong Cốc","ghiChu":"@c0798"},{"ten":"Hàn Lập","tag":"dong-minh","quanHe":"Đồng môn Hoàng Phong Cốc, nhận ra thân phận qua dung mạo và lời đồn","ghiChu":"@c0799"},{"ten":"Nữ tu kết nghĩa với Trần Xảo Thiên","tag":"ban-be","quanHe":"Nghĩa muội trong nhóm ba kết nghĩa, thuộc Hóa Đao Ổ","ghiChu":"@c0799"},{"ten":"Nam tu áo lam kết nghĩa với Trần Xảo Thiên","tag":"ban-be","quanHe":"Nghĩa đệ trong nhóm ba kết nghĩa","ghiChu":"@c0799"}],"tuiDo":{}},"nguon":["@c0798","@c0799"]},{"id":"tu-si-cao-ngu-linh-tong","name":"Tu sĩ cao Ngự Linh Tông","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Ngự Linh Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kết Đan trung kỳ","trangThai":"song","vaiTro":"Đệ tử Ngự Linh Tông, nhận ra Hàn Lập từ cuộc chiến biên giới","tinhCach":"Hung hãn khi đánh kẻ yếu, hoảng sợ trước cường giả","blurb":"Tu sĩ vóc dáng cao to thuộc Ngự Linh Tông, tu vi Kết Đan trung kỳ. Khu sử cự đại phi nga phun độc phấn tấn công phe Trần Xảo Thiên, nhận ra Hàn Lập là Lạc Vân Tông Hàn tiền bối từ cuộc chiến biên giới, hoảng sợ tuân lệnh rút lui.","tabs":{"diem":[{"text":"Nhận ra Hàn Lập từ cuộc chiến biên giới, hoảng sợ lập tức tuân lệnh thu quân","chuong":"@c0798"}],"kinhLich":[{"mucCt":"vua","text":"Cùng tu sĩ lùn khu sử cự đại phi nga phun độc phấn tấn công nhóm Trần Xảo Thiên. Nhận ra Hàn Lập là Lạc Vân Tông Hàn tiền bối từ cuộc chiến biên giới, hoảng sợ lập tức thu linh trùng vào túi linh thú, vội vã cáo từ rút lui.","anchor":"Người là Lạc Vân Tông Hàn tiền bối!","bridge":true,"khoang":"@c0798"}],"nhanMach":[{"ten":"Hàn Lập","tag":"khac","quanHe":"Nguyên Anh tiền bối Lạc Vân Tông, từng thấy ở cuộc chiến biên giới","ghiChu":"@c0798"}],"tuiDo":{}},"nguon":["@c0798"]},{"id":"tran-xao-thien-s","name":"Trần Xảo Thiến","cn":"陈巧倩","aliases":[],"gioiTinh":"nu","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c0798","importance":"normal","mucCt":"vua","tieuDe":"Xác nhận đã qua đời hơn trăm năm trước","text":"Qua lời Trần Xảo Thiên — anh trai, xác nhận Trần Xảo Thiến không phải Kết Đan tu sĩ, đã mắc quái bệnh qua đời hơn trăm năm trước. Hàn Lập nhớ lại lần cuối cùng gặp mặt nàng khi nàng nói sắp lập gia đình.","anchor":"Gia muội cũng không phải là Kết Đan Tu Sĩ. Từ hơn trăm năm trước gặp phải một hồi quái bệnh đã qua đời rồi."},{"importance":"normal","mucCt":"vua","chuong":"@c0799","tieuDe":"Được tiết lộ sống độc thân đến cuối đời","text":"Trần Xảo Thiên kể cho Hàn Lập: năm đó gia tộc Trần định gả Thiến nhưng bên kia ngả phe ma đạo nên hủy hôn. Sau đó Thiến trở nên trầm mặc ít nói, không quan tâm nam nhân, độc thân đến cuối đời.","anchor":"Sau đó gia muội trở nên trầm mặc ít nói, đối với nam nhân cũng không quan tâm và vẫn độc thân đến cuối đời"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0798","@c0799"]},{"id":"nam-lung-hau","name":"Nam Lũng Hầu","cn":"南陇侯","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0798","importance":"bridge","mucCt":"gon","text":"Hàn Lập chưa tìm được Nam Lũng Hầu nhưng tự tin hắn sẽ chủ động tìm đến nhờ Lưỡng nghi hoàn.","anchor":"phỏng chừng Nam Lũng Hầu cũng sẽ chủ động tìm đến cửa"},{"mucCt":"ky","text":"Đã tìm kiếm Hàn Lập hơn một tháng, mừng rỡ khi gặp. Bán tín bán nghi trước danh tiếng Hàn Lập giết Nguyên Anh Trung Kỳ Ma Tông Tần quốc. Tiết lộ chính hắn và Lỗ trưởng lão cố ý truyền phương pháp nhập cốc ra ngoài nhằm phá kế hoạch độc chiếm của Quỷ Linh Môn. Nhắc chuyện Lưỡng Nghi Hoàn bị Quỷ Linh Môn đoạt, nghiến răng căm hận, tuyên bố sau khi ra cốc sẽ tính sổ. Nguyên khí đã khôi phục vài thành.","anchor":"Nếu Quỷ Linh Môn tên kia âm hiểm tiểu nhân đoạt được Lưỡng Nghi Hoàn, Bản hầu đã trực tiếp giết người đoạt bảo rồi","bridge":true,"khoang":"@c0801"},{"mucCt":"ky","text":"Đứng chờ Hàn Lập trên đỉnh tiểu sơn phía tây Trụy Ma Cốc, lo lắng nôn nóng, nhấn mạnh nhất định cần Hàn Lập, nếu thiếu sẽ về tay không. Giải thích về hỏa thiềm thú theo di thư Thương Khôn Thượng Nhân, cho rằng con thú tu luyện rất lâu vì không có thiên địch trong cốc. Lấy ra cảm ứng linh treo bên hông để cảnh báo khe hở không gian trên đường đi. Dẫn ba người bay hơn nửa ngày đến gần nội cốc, dùng ngọc bội trắng phá huyễn thuật che cửa thông đạo bí mật, mở lối vào nội cốc.","anchor":"trong di thư của Thương Khôn Thượng Nhân nói thì xác thực con thú này vô cùng đáng sợ","bridge":true,"khoang":"@c0807"},{"chuong":"@c0808","importance":"normal","mucCt":"ky","tieuDe":"Thăm dò thông đạo sương mù, chuẩn bị chiến cự mãng","text":"Dẫn đường đến thông đạo nội cốc theo di thư Thương Khôn Thượng Nhân. Thả linh điểu vàng kim từ linh thú túi bay vào sương mù thăm dò, qua thần cảm xác nhận linh điểu bị cự mãng nuốt chết. Đồng ý diệt khẩu Hoàng Thiên Minh, khen Hàn Lập nhìn thấu ẩn thuật. Phun ra kim sắc tiểu kiếm kích hoạt thành cự kiếm dài năm sáu trượng, sẵn sàng giao chiến.","anchor":"hóa thành một thanh kim sắc cự kiếm dài độ năm sáu trượng phiêu phù phía trên đầu Nam Lũng Hầu"},{"mucCt":"ky","text":"Điều khiển Kim sắc cự kiếm (bổn mạng pháp bảo bồi luyện hơn trăm năm) tấn công cự mãng nhưng bị lục quang hộ thể hất văng, sau đó bị cự mãng nuốt vào bụng cùng Kinh Long chung của Hàn Lập. Cố thúc dục phi kiếm phá ra nhưng bị cầm trụ hoàn toàn không nhúc nhích, lo lắng vì tâm thần tương liên — pháp bảo hao tổn thì chủ cũng bị thương nặng. Rút chiếc nhẫn xanh biếc có ký hiệu nhiều màu chớp động làm vũ khí thay thế.","anchor":"Kiện kim sắc phi kiếm này chính là bổn mạng pháp bảo do hắn tiêu tốn hơn trăm năm mới bồi luyện ra được","bridge":true,"khoang":"@c0809"},{"mucCt":"ky","text":"Phóng chiếc nhẫn xanh biếc huyễn hóa hơn trăm cái, bản thể ghìm chặt vị trí thất thốn dưới đầu cự mãng chế trụ nó để phối hợp Thiên Trọng Phong của Hàn Lập nghiền nát. Thu hồi kim sắc phi kiếm và nhẫn từ xác rắn, nhận một viên nội đan. Giải thích cự mãng thiếu nhục sí nên không phải tam thủ ô xà thật, nhắc chuyện Thương Khôn Thượng Nhân năm xưa bị hỏa thiềm thú đánh đại thương nguyên khí. Cho biết sơn động phía trước có bắc cực nguyên quang dài hơn mười dặm, cần lưỡng nghi hoàn của Hàn Lập mới qua, và không thể đi đường khác qua thạch bích.","anchor":"Nếu không, chúng ta làm sao có thể dễ dàng đắc thủ như thế","bridge":true,"khoang":"@c0810"},{"importance":"bridge","mucCt":"vua","chuong":"@c0811","tieuDe":"Nhắc nhở mục tiêu chính","text":"Trấn định trước mỏ Cương Ngân Sa, nhắc nhở Lỗ Vệ Anh rằng mục tiêu chính là linh dược kéo dài tuổi thọ và gia tăng cảnh giới, không nên lãng phí thời gian khai thác. Khi gặp Bắc Cực Nguyên Quang, nghiêm nghị cảnh báo cả nhóm tuyệt đối không được tiết linh lực hay dùng pháp bảo ngoại trừ Lưỡng Nghi hoàn.","anchor":"Một khi linh lực trên người tiết ra ngoài bị Bắc Cực Nguyên Quang cảm ứng được thì ba người chúng ta tuyệt đối chỉ có con đường chết"},{"chuong":"@c0812","importance":"bridge","mucCt":"gon","text":"Thối lui về phía sau Hàn Lập lấy hắn làm chủ, bám theo vượt qua vùng Bắc Cực Nguyên Quang dưới sự bảo hộ của Lưỡng Nghi hoàn.","anchor":"sắc mặt ngưng trọng thối lui về phía sau Hàn Lập gần một trượng, lấy hắn làm chủ"},{"mucCt":"ky","text":"Dẫn đầu ba người bước vào nội cốc Trụy Ma Cốc. Tiết lộ thông tin quan trọng từ di thư Thương Khôn Thượng Nhân: khe hở không gian vô hình sẽ không di động, và Thương Khôn Thượng Nhân năm xưa thoát khỏi Trụy Ma Cốc nhờ thần thông cảm ứng khe hở không gian chứ không phải may mắn. Đã thuộc lòng lộ tuyến không cần lấy ngọc giản, dẫn đường phi hành theo đường quanh co cổ quái hơn nửa ngày. Đánh giá Hàn Lập là chủ lực đối phó Hỏa Thiềm thú, quyết tâm giữ hắn nhập bọn. Sau hơn nửa ngày phi hành đột ngột dừng lại, sắc mặt âm tình bất định, cảnh báo phiền toái thậm chí nguy hiểm liên quan đến hai ngọn núi cao lớn phía trước.","anchor":"Hai vị, ta nghĩ chúng ta có thể gặp phải một ít phiền toái","bridge":true,"khoang":"@c0813"},{"mucCt":"ky","text":"Tiết lộ hai con đường đến sào huyệt Hỏa Thiềm thú: ngọn núi trái có hơn mười con Phi Thiên Tử Vân hạt tím đen sống mấy vạn năm, ngọn phải có khe hở không gian vô hình dày đặc. Thừa nhận không có thần thông cảm ứng khe hở không gian như Thương Khôn Thượng Nhân nên chọn đường Tử Vân hạt. Ban đầu tính ba người liên thủ chiến đấu nhưng dao động trước phản ứng sợ hãi của Lỗ Vệ Anh, nhanh chóng đồng ý kế dẫn dụ của Hàn Lập. Đổ hết việc lên Hàn Lập chỉ bằng vài câu, bị Hàn Lập nghi cố tình giấu thông tin đến phút cuối.","anchor":"chỉ cần vài câu là đã đem hết thảy mọi việc đổ lên người mình","bridge":true,"khoang":"@c0814"},{"mucCt":"vua","text":"Khen ngợi Hàn Lập sau khi vượt qua lãnh địa Tử Vân hạt. Giới thiệu sào huyệt Hỏa Thiềm thú dưới chân núi đỏ và giải thích cơ chế hồi phục của thú trong dung nham theo lời Thương Khôn Thượng Nhân. Bác bỏ đề xuất trực tiếp dùng Băng thuộc tính diệt thú của Lỗ Vệ Anh, đề nghị thiết lập pháp trận Thủy thuộc tính trước rồi dẫn dụ thú ra ngoài tiêu diệt, sau đó triển khai bộ khí cụ bày trận đã chuẩn bị sẵn.","anchor":"ta đã chuẩn bị một bộ khí cụ bày trận Thủy thuộc tính","bridge":true,"khoang":"@c0815"},{"importance":"normal","chuong":"@c0815","tieuDe":"Dẫn đường và chủ trì kế bày trận dụ thú","mucCt":"vua","text":"Dẫn đường tới Dung Nham Chi Địa, chỉ ra động quật dưới chân núi lửa cao mấy ngàn trượng là sào huyệt Hỏa Thiềm thú, bên trong có di hài tu sĩ thượng cổ. Bác kế đánh thẳng của Lỗ Vệ Anh vì theo lời Thương Khôn Thượng Nhân, con thú trọng thương cỡ nào chỉ cần nhảy vào dung nham là hồi phục như cũ. Đề xuất bày trận trước rồi dụ thú ra diệt, đem bộ khí cụ bày trận Thủy thuộc tính đã chuẩn bị sẵn ra chủ trì đại trận.","anchor":"ta đã chuẩn bị một bộ khí cụ bày trận Thủy thuộc tính"},{"importance":"bridge","mucCt":"vua","chuong":"@c0817","tieuDe":"Chiến đấu Hỏa Thiềm thú và cảnh giác Hàn Lập","text":"Cùng Lỗ Vệ Anh điều khiển bảo vật ngăn chặn Hỏa Thiềm thú thoát pháp trận nhưng chậm một bước. Sau khi yêu thú bị trảm đầu, định triệt bỏ pháp trận nhưng bị Hàn Lập ngăn lại, tay tự động đặt lên túi trữ vật lộ vẻ cảnh giác.","anchor":"một tay tự động đặt lên túi trữ vật bên hông"},{"importance":"bridge","mucCt":"vua","chuong":"@c0818","tieuDe":"Phát hiện Thanh Tàm bào và linh liệu cổ tu sĩ","text":"Thất thanh nhận ra Bất diệt chi thể của Hỏa Thiềm thú, động tâm trước yêu đan nhưng tự xét không bằng Hàn Lập nên bỏ ý. Đề xuất vào sào huyệt tìm di hài mà Thương Khôn thượng nhân đề cập, nhận ra Thanh Tàm bào dệt từ tơ tằm cổ xưa và thu lấy, mở túi trữ vật đổ ra linh liệu cùng nhiều cổ bảo.","anchor":"Loại áo này được dệt từ một loại tơ tằm cổ xưa, có thể ngăn cản thần thức tu sĩ dò xét"},{"importance":"bridge","mucCt":"vua","chuong":"@c0819","tieuDe":"Phân chia bảo vật sau trận chiến","text":"Mở hộp ngọc bằng kim quang phá cấm chế bạch quang, phát hiện ngọc giản Thất Diễm phiến bên trong. Mở hai dược bình, phát hiện hai viên cổ linh đan xanh biếc tỏa thanh hương. Vì sắp hết thọ nguyên nên rất cần linh đan, chủ động nhượng bộ cho Hàn Lập chọn trước hai kiện cổ bảo để đổi lấy linh đan. Cuối cùng được một viên cổ linh đan và chia phần cổ bảo còn lại.","anchor":"cổ bảo của hắn cơ hồ đã bị bọn người Quỷ Linh Môn hủy gần hết"},{"mucCt":"ky","text":"Nhận một kiện cổ bảo, từ chối cùng Hàn Lập xuất cốc, tiết lộ Thương Khôn thượng nhân đã tìm được Truyền Tống trận ra ngoại cốc. Sau khi Hàn Lập rời đi, thả linh cầm Thiên Lý ly xác nhận Hàn Lập đã xa. Cùng Lỗ Vệ Anh thảo luận: theo di thư Thương Khôn thượng nhân, bộ hài cốt cổ tu sĩ là chìa khóa phá Huyết chú chi môn, phía sau cánh cửa chứa trọng bảo. Quyết định nhanh chóng hành động.","anchor":"Về phần nguyên nhân bên trong, thứ cho bản hầu không thể nói rõ với Lỗ huynh được","bridge":true,"khoang":"@c0820"},{"mucCt":"ky","text":"Nam Lũng Hầu dẫn Lỗ Vệ Anh vào thông đạo dưới sào huyệt Tử Vân Hạt tìm Huyết Chú Chi Môn. Hắn tiết lộ thông tin Huyết Chú Chi Môn là bí sự truyền miệng riêng, không nằm trong di thư Thương Khôn Thượng Nhân, và cố ý gạt Hàn Lập ra ngoài. Hắn dùng Phân Thủy Kỳ rẽ nước thủy đàm sâu ba trăm trượng, rồi dùng ngọc bội trắng vén màn nước lộ ra thạch môn Huyết Chú Chi Môn — hình vòm cao ba trượng, lóe huyết sắc hồng quang, điêu khắc đầu quỷ một sừng.","anchor":"Sự tình có quan hệ đến huyết chú chi môn chính là lúc trước bổn Hầu cùng tên tặc tử họ Vân cùng tìm thấy di thư của Thương Khôn thượng nhân nhưng cũng không nói tới chuyện này","bridge":true,"khoang":"@c0821"},{"mucCt":"vua","text":"Cùng Lỗ Vệ Anh tới thạch môn đáy thủy đàm, xác nhận đây là cửa vào do Thượng cổ tu sĩ dùng tinh huyết toàn thân phong ấn. Đề xuất bố trí mấy tầng cấm chế ngoài cửa phòng đường lui, cùng Lỗ Vệ Anh lấy trận khí cụ thiết trí pháp trận tại đáy thủy đàm và chuẩn bị giải huyết cấm.","anchor":"Cửa vào này là do Thượng cổ tu sĩ dùng tinh huyết toàn thân để phong ấn","bridge":true,"khoang":"@c0822"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0798","@c0801","@c0807","@c0808","@c0809","@c0810","@c0811","@c0812","@c0813","@c0814","@c0815","@c0816","@c0817","@c0818","@c0819","@c0820","@c0821","@c0822"],"trangThai":"song"},{"id":"lenh-ho-lao-to","name":"Lệnh Hồ lão tổ","cn":"","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0798","importance":"bridge","mucCt":"gon","text":"Được Trần Xảo Thiên nhắc tới khi hỏi Hàn Lập có quen biết Lệnh Hồ tổ sư không.","anchor":"Dám hỏi tiền bối có quen biết cùng Lệnh Hồ tổ sư?"},{"importance":"bridge","mucCt":"gon","chuong":"@c0799","tieuDe":"Nhắc tên","text":"Được nam tu áo lam nhắc: từng muốn khuyên Hàn Lập quay về Hoàng Phong Cốc nhưng Hàn Lập không muốn.","anchor":"Lệnh Hồ sư bá của quý cốc từng muốn khuyên người này quay về Hoàng Phong Cốc nhưng người này tựa hồ không muốn trở về"},{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Mặc hoàng bào, sắc mặt sốt ruột, cùng trưởng lão Yểm Nguyệt Tông và lão giả lạ mặt song song phi hành hướng Trụy Ma Cốc.","anchor":"Trong đó một hoàng bào lão giả sắc mặt sốt ruột, đúng là Hoàng Phong Cốc Lệnh Hồ lão tổ"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0798","@c0799","@c0802"],"trangThai":"song"},{"id":"ngan-nguyet","name":"Ngân Nguyệt","gioiTinh":"nu","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0799","tieuDe":"Tu luyện trong động phủ mới","text":"Được Hàn Lập thả ra trong động phủ mới tại Vạn Linh Sơn để tự tu luyện.","anchor":"Trước tiên hắn thả Ngân Nguyệt ra, để nàng ở trong động phủ tự tu luyện"},{"chuong":"@c0800","importance":"bridge","mucCt":"vua","text":"Thay Hàn Lập theo dõi tình hình ngoài động phủ suốt mấy tháng bế quan, bẩm báo khi Hàn Lập xuất quan. Thân thể yêu hồ bị Hàn Lập thu vào tay áo trước khi rời đi.","anchor":"hắn đi một gian mật thất khác quan sát Thiên tuyệt ma thi nọ"},{"importance":"normal","mucCt":"vua","chuong":"@c0819","tieuDe":"Nhận ra Thất Diễm phiến là Thông Thiên Linh Bảo","text":"Nhận ra Thất Diễm phiến chính là một loại Thông Thiên Linh Bảo (đứng vị trí rất thấp, gần đội sổ), vui mừng thông báo cho Hàn Lập qua thần thức. Xảy ra khẩu chiến ngắn với Đại Diễn Thần Quân vì còn hận chuyện lão từng đề xuất mượn cô để nghiên cứu.","anchor":"nếu ta không nhớ sai thì nó là một loại Thông Thiên Linh Bảo"},{"importance":"bridge","mucCt":"vua","chuong":"@c0820","tieuDe":"Nhận ra địa đồ Trụy Ma Cốc","text":"Giao tiếp với Hàn Lập trên đường phi hành, nhận ra mảnh vải giấu trong Thanh Tàm bào là địa đồ vẽ Trụy Ma Cốc.","anchor":"Đây là một khối địa đồ, hình như vẽ Trụy Ma Cốc"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0799","@c0800","@c0819","@c0820"],"trangThai":"song","cn":"银月"},{"id":"nu-tu-ket-nghia-tran-xao-thien","name":"Nữ tu kết nghĩa với Trần Xảo Thiên","gioiTinh":"nu","theLuc":[{"ten":"Hóa Đao Ổ","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Nghĩa muội của Trần Xảo Thiên trong nhóm ba người kết nghĩa, thuộc Hóa Đao Ổ. Hỏi han về lai lịch Hàn Lập, kinh ngạc khi biết danh tính.","vaiTro":"Nghĩa muội của Trần Xảo Thiên, thuộc Hóa Đao Ổ","tinhCach":"Tò mò; tôn kính cường giả","tabs":{"diem":[{"text":"Nghĩa muội trong nhóm ba kết nghĩa với Trần Xảo Thiên, thuộc Hóa Đao Ổ","chuong":"@c0799"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0799","tieuDe":"Hỏi lai lịch Hàn Lập","text":"Cùng nam tu áo lam hỏi Trần Xảo Thiên về lai lịch Hàn Lập, kinh ngạc khi biết danh tính.","anchor":"Ngày xưa xuất thân từ Hoàng Phong Cốc chúng ta, ngày nay lại từng từ trong tay Mộ Lan thần sư toàn vẹn thoát đi"}],"tuViMoc":[],"nhanMach":[{"ten":"Trần Xảo Thiên","tag":"ban-be","quanHe":"Đại ca trong nhóm ba kết nghĩa","ghiChu":"@c0799"}],"tuiDo":{}},"nguon":["@c0799"]},{"id":"nam-tu-ao-lam-ket-nghia-tran-xao-thien","name":"Nam tu áo lam kết nghĩa với Trần Xảo Thiên","gioiTinh":"nam","trangThai":"song","blurb":"Nghĩa đệ của Trần Xảo Thiên trong nhóm ba người kết nghĩa. Nhắc việc Lệnh Hồ sư bá từng muốn mời Hàn Lập về Hoàng Phong Cốc.","vaiTro":"Nghĩa đệ của Trần Xảo Thiên","tinhCach":"Am hiểu tin tức giới tu luyện","tabs":{"diem":[{"text":"Nghĩa đệ trong nhóm ba kết nghĩa với Trần Xảo Thiên, biết nhiều tin giới tu luyện","chuong":"@c0799"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0799","tieuDe":"Bàn luận lai lịch Hàn Lập","text":"Nhắc việc Kim Thư ngân bút pháp bảo và Lệnh Hồ sư bá từng muốn mời Hàn Lập về Hoàng Phong Cốc.","anchor":"Lệnh Hồ sư bá của quý cốc từng muốn khuyên người này quay về Hoàng Phong Cốc nhưng người này tựa hồ không muốn trở về"}],"tuViMoc":[],"nhanMach":[{"ten":"Trần Xảo Thiên","tag":"ban-be","quanHe":"Đại ca trong nhóm ba kết nghĩa","ghiChu":"@c0799"}],"tuiDo":{}},"nguon":["@c0799"]},{"id":"bach-thu-quan","name":"Bạch Thư Quân","cn":"白书君","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Đang cùng nữ tu họ Viên mua Kim linh tử tại phường thị. Bị Hàn Lập ném Thiên cực lệnh, nhận ra Hàn Lập là tồn tại chỉ thấp hơn tam đại tu sĩ, hoảng sợ cung kính dẫn đường đến chỗ ở Lỗ Vệ Anh.","anchor":"Thanh niên sau khi thấy rõ lệnh bài thì cả kinh, ngẩng đầu nhìn kỹ người nọ rồi không khỏi hoảng sợ bật kêu lên thất thanh","bridge":true,"khoang":"@c0800"}],"nhanMach":[{"ten":"Nữ tu họ Viên","tag":"dong-hanh","quanHe":"Nữ tu đi cùng mua Kim linh tử tại phường thị.","ghiChu":"@c0800"},{"ten":"Nữ tử họ Lỗ","tag":"dong-hanh","quanHe":"Hậu nhân Lỗ Vệ Anh, đi cùng.","ghiChu":"@c0800"}]},"nguon":["@c0800"]},{"id":"lo-ve-anh","name":"Lỗ Vệ Anh","cn":"吕威英","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c0800","importance":"normal","mucCt":"vua","tieuDe":"Đón Hàn Lập tại chỗ ẩn cư","text":"Ẩn cư tại tòa núi nhỏ trong Vạn Linh Sơn, dùng tiểu tu di cấm pháp che giấu chỗ ở. Vui mừng mở thạch môn đón Hàn Lập, đuổi đệ tử và hậu nhân ra ngoài để nói chuyện riêng.","anchor":"Ngươi rốt cục đã tìm đến. Nếu còn không hiện thân thì lão phu chỉ sợ cũng phải dùng phóng xuất thần thực tự tìm tòi"},{"mucCt":"vua","text":"Chủ động phủ nơi ba người hội họp. Phân tích chiến lược Quỷ Linh Môn dùng Trụy Ma Lệnh làm nhân tình và dùng người khác dò đường. Đề xuất ba người chia đều bảo vật, đáp ứng yêu cầu nội đan Hỏa Thiềm cho Hàn Lập.","anchor":"bọn họ cố nhiên không cách nào có thể tự mình chiếm đoạt","bridge":true,"khoang":"@c0801"},{"importance":"bridge","mucCt":"vua","chuong":"@c0807","text":"Ngồi xếp bằng dưỡng thần trên đỉnh tiểu sơn chờ Hàn Lập, trấn an Nam Lũng Hầu, phán đoán hỏa thiềm thú trong cốc có thể là biến dị, cùng hai người lên đường tiến về nội cốc.","anchor":"Con cổ thú này ở thời thượng cổ cũng không phải là nổi danh như thế"},{"chuong":"@c0808","importance":"normal","mucCt":"ky","tieuDe":"Diệt khẩu Hoàng Thiên Minh, chuẩn bị phá yêu vụ","text":"Nhận ra sương mù bất thường mà di thư Thương Khôn Thượng Nhân không đề cập, suy luận cự mãng đến thông đạo sau khi di thư được viết. Quyết đoán tuyên bố diệt khẩu Hoàng Thiên Minh dù hắn cùng chính đạo liên minh, dùng Cự Phong Kỳ hóa cơn lốc băm nát hắn, thu túi trữ vật và ẩn hình ngọc phù. Chuẩn bị dùng Cự Phong Kỳ thổi tan yêu vụ cự mãng.","anchor":"bản thân hắn cũng bị vô số phong nhận trong cơn lốc băm thành vạn đoạn, chỉ còn một mảnh huyết vũ"},{"mucCt":"vua","text":"Phát động pháp kỳ tạo hơn mười phong long quét sương mù, bắt pháp quyết kích nổ cơn lốc quét sạch biển sương lộ ra thân hình cự mãng. Thu pháp kỳ khi thấy pháp bảo hai người bị nuốt, chuyển sang dùng bạch sắc hỏa cầu quỷ dị từ phù lục.","anchor":"mấy cái trương phù khinh khinh phiêu phiêu bắn ra rồi lập tức ánh bạch quang bạo xạ xuất hiện hơn mười khối hỏa cầu quỷ dị sáng trắng chói mắt","bridge":true,"khoang":"@c0809"},{"mucCt":"ky","text":"Phóng hơn mười bạch hỏa cầu tấn công cự mãng, thao khống bạch hỏa biến thành hỏa liên cuốn giữ cự mãng khi nó cố thoát Thiên Trọng Phong. Bắn bạch sắc quang tuyến chém rơi đầu rắn cuối cùng kết liễu cự mãng. Lấy ba viên thanh sắc nội đan từ ba đầu rắn, chia mỗi người một viên. Tại thạch bích dẫn vào nội cốc, thử bắn phi đao pháp bảo dạng đoản nhận tấn công thạch bích để tìm đường khác.","anchor":"quang luyện này là một cái đoản nhận kỳ lạ, phảng phất là phi đao pháp bảo hiếm thấy nào đó","bridge":true,"khoang":"@c0810"},{"importance":"bridge","mucCt":"vua","chuong":"@c0811","tieuDe":"Phát hiện Cương Ngân Sa rồi tỉnh ngộ","text":"Dùng phi đao chém thạch bích phát hiện Cương Ngân Sa, bị bảo vật làm lóa mắt muốn ở lại khai thác. Sau khi được Nam Lũng Hầu nhắc nhở thì tỉnh ngộ, cảm tạ và tiếp tục đi sâu vào động.","anchor":"Lão phu nhất thời hồ đồ bị bảo vật làm lóa mắt, thiếu chút nữa quên mất mục đích chính của chuyến đi này"},{"chuong":"@c0812","importance":"bridge","mucCt":"gon","text":"Cùng Nam Lũng Hầu thối lui theo sau Hàn Lập, vượt qua Bắc Cực Nguyên Quang an toàn dưới sự bảo hộ của Lưỡng Nghi hoàn.","anchor":"sắc mặt Nam Lũng Hầu và lão giả họ Lỗ cũng trầm trọng"},{"importance":"bridge","mucCt":"gon","chuong":"@c0813","tieuDe":"Vào nội cốc, lo lắng khe hở không gian","text":"Thất thanh khi phát hiện khe hở không gian dày đặc trong nội cốc, nêu lo ngại khe hở vô hình nếu di động thì lộ tuyến không an toàn; dọc đường sắc mặt âm trầm thường xuyên nhìn về phía xa, Hàn Lập đoán lão đang tìm cơ hội mạo hiểm lấy bảo vật vì áp lực đại hạn sắp tới.","anchor":"Khe hở không gian!!! Sao lại nhiều như vậy? Chúng còn di chuyển nữa chứ???"},{"mucCt":"ky","text":"Kiên quyết phản đối đi qua đám Phi Thiên Tử Vân hạt, tiết lộ khi còn trẻ từng đại biểu Thiên Cực Môn tham gia vây sát Tử Vân hạt ở Vọng Thủy Quốc, trực tiếp chứng kiến sự đáng sợ của chúng. Nhận ra bình Bích Cưu của Hàn Lập và nhắc tới Phúc Thi chi độc của Ngụy Vô Nhai cũng thuộc Thập Tuyệt độc. Cuối cùng chấp nhận kế dẫn dụ.","anchor":"Khi còn trẻ, ta đã đại biểu cho Thiên Cực Môn tham gia vây sát Tử Vân hạt","bridge":true,"khoang":"@c0814"},{"importance":"bridge","mucCt":"vua","chuong":"@c0815","tieuDe":"Bị âm thanh Tử Vân hạt công kích, đề xuất bị bác","text":"Bị công kích âm thanh Tử Vân hạt làm thân hình chấn động nhưng khôi phục được, khen ngợi Hàn Lập rồi đề xuất dùng công pháp Băng thuộc tính của Hàn Lập trực tiếp diệt Hỏa Thiềm thú nhưng bị Nam Lũng Hầu bác bỏ.","anchor":"Lấy công pháp Băng thuộc tính của Hàn đạo hữu làm chính, hai người bọn ta làm phụ"},{"importance":"normal","chuong":"@c0815","tieuDe":"Vượt ải và bàn kế diệt Hỏa Thiềm thú","mucCt":"vua","text":"Cùng chịu âm công của đàn Tử Vân hạt rồi vượt ải an toàn, khen công của Bích Cưu độc và khôi lỗi. Đề xuất đánh thẳng vào sào huyệt, lấy công pháp Băng thuộc tính của Hàn Lập làm chủ lực, hai người còn lại làm phụ. Nghe Nam Lũng Hầu phân tích đặc tính hồi phục trong dung nham của Hỏa Thiềm thú thì không phản đối kế bày trận dụ thú.","anchor":"Lấy công pháp Băng thuộc tính của Hàn đạo hữu làm chính"},{"importance":"bridge","mucCt":"vua","chuong":"@c0817","tieuDe":"Chiến đấu và cảnh giác sau khi trảm thú","text":"Điều khiển bích lục chỉ hoàn huyễn hóa hàng trăm ảo ảnh và hai đạo phi qua lam sắc hóa băng mãng tấn công Hỏa Thiềm thú nhưng hiệu quả hạn chế. Lo lắng yêu cầu Hàn Lập dùng Băng thuộc tính khắc chế quang thuẫn tái sinh của yêu thú. Vui mừng khi yêu thú bị trảm đầu nhưng sau đó lộ sắc cảnh giác khi Hàn Lập ngăn triệt pháp trận.","anchor":"linh thuẫn Hỏa thuộc tính trên thân con Hỏa Thiềm thú kia thực sự liên miên bất tuyệt, không thể diệt trừ hết"},{"importance":"bridge","mucCt":"vua","chuong":"@c0818","tieuDe":"Đặt vấn đề phân chia cổ bảo","text":"Cả kinh trước Bất diệt chi thể và Thanh Tàm bào phản xạ thần thức, động tâm trước yêu đan nhưng bỏ ý vì đánh giá không thắng nổi Hàn Lập. Chú ý hộp ngọc trắng và dược bình đen, đặt vấn đề phân chia bảo vật.","anchor":"Chúng ta sẽ phân chia bảo vật này ra sao đây? Chẳng lẽ một người lấy hai kiện?"},{"importance":"bridge","mucCt":"vua","chuong":"@c0819","tieuDe":"Phân chia bảo vật sau trận chiến","text":"Đề nghị mở hộp ngọc và dược bình xem giá trị trước khi phân chia. Đánh giá ngọc giản Thất Diễm phiến ít giá trị thực tế, chỉ dùng nghiên cứu luyện khí. Vì sắp hết thọ nguyên nên khẩn trương khi Hàn Lập đòi linh đan, chủ động đề xuất cho Hàn Lập chọn thêm cổ bảo để đổi. Cuối cùng được một viên cổ linh đan.","anchor":"Thọ nguyên của đạo hữu còn rất nhiều, sau này sẽ có thời gian tìm linh đan"},{"mucCt":"ky","text":"Nhận một kiện cổ bảo, bố trí tầng cách âm trước khi thảo luận. Bán tín bán nghi về khả năng Hàn Lập ẩn thân gần đó, nhận xét Hàn Lập tu vi không cao nhưng khiến người cảm giác cao thâm mạc trắc. Đồng ý với Nam Lũng Hầu nhanh chóng đến Huyết chú chi môn lấy trọng bảo.","anchor":"Rõ ràng tu vi không cao nhưng lại khiến cho chúng ta có cảm giác cao thâm mạc trắc","bridge":true,"khoang":"@c0820"},{"mucCt":"ky","text":"Lỗ Vệ Anh đi cùng Nam Lũng Hầu, thừa nhận tin bảy tám phần về sự tồn tại của Huyết Chú Chi Môn. Lão ngầm nhắc nhở Nam Lũng Hầu rằng mình biết bị lợi dụng vì cần hai tu sĩ Nguyên Anh mới mở được. Khi xuống đáy thủy đàm sâu ba trăm trượng, lão cảm thấy lo lắng, và khi nhìn thấy thạch môn Huyết Chú Chi Môn thì hoảng sợ bất an.","anchor":"Không biết vì sao khi nhìn thấy cánh cửa này thì hắn có chút hoảng sợ, trong lòng cảm thấy bất an","bridge":true,"khoang":"@c0821"},{"chuong":"@c0822","importance":"bridge","mucCt":"vua","text":"Cùng Nam Lũng Hầu tới thạch môn cửa vào Linh Miểu Viên, lo lắng huyết khí ma khí trên cửa, đồng ý bố trí cấm chế cẩn thận rồi cùng thiết trí pháp trận đáy thủy đàm.","anchor":"Cửa vào này là do Thượng cổ tu sĩ dùng tinh huyết toàn thân để phong ấn"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0800","@c0801","@c0807","@c0808","@c0809","@c0810","@c0811","@c0812","@c0813","@c0814","@c0815","@c0816","@c0817","@c0818","@c0819","@c0820","@c0821","@c0822"],"aliases":["Lỗ trưởng lão","lão giả họ Lỗ","Lỗ huynh"]},{"id":"nu-tu-ho-vien","name":"Nữ tu họ Viên","aliases":["Viên sư muội"],"gioiTinh":"nu","trangThai":"song","theLuc":[{"ten":"Thiên Cực Môn","trangThai":"gan-bo"}],"blurb":"Nữ tu bạch y đi cùng Bạch Thư Quân, tướng mạo bình thường nhưng có đôi mắt đẹp mê người, đang tìm Kim linh tử để luyện Hóa Tức đan.","vaiTro":"Đệ tử Thiên Cực Môn, đồng hành Bạch Thư Quân","tinhCach":"Cung kính trước bậc tiền bối","tabs":{"diem":[{"text":"Tướng mạo bình thường nhưng có đôi mắt đẹp mê người.","chuong":"@c0800"}],"kinhLich":[{"chuong":"@c0800","importance":"bridge","mucCt":"gon","text":"Đi cùng Bạch Thư Quân tại phường thị mua Kim linh tử để luyện Hóa Tức đan.","anchor":"Bạch sam nữ tử này tướng mạo bình thường nhưng có một đôi mắt đẹp mê người, lệ thủy lưng tròng"}],"tuViMoc":[],"nhanMach":[{"ten":"Bạch Thư Quân","tag":"dong-hanh","quanHe":"Đồng môn, đi cùng mua nguyên liệu.","ghiChu":"@c0800"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0800"]},{"id":"nu-tu-ho-lo","name":"Nữ tử họ Lỗ","gioiTinh":"nu","trangThai":"song","theLuc":[{"ten":"Thiên Cực Môn","trangThai":"gan-bo"}],"blurb":"Hậu nhân của Lỗ Vệ Anh (gia thúc tổ), đệ tử Thiên Cực Môn, đi cùng Bạch Thư Quân.","vaiTro":"Hậu bối Lỗ Vệ Anh, đệ tử Thiên Cực Môn","tinhCach":"Cung kính, ngưỡng mộ cao nhân","tabs":{"diem":[{"text":"Hậu nhân của Lỗ Vệ Anh, Lỗ trưởng lão là gia thúc tổ.","chuong":"@c0800"}],"kinhLich":[{"chuong":"@c0800","importance":"bridge","mucCt":"gon","text":"Gặp Hàn Lập khi dẫn đường cùng Bạch Thư Quân đến chỗ ở Lỗ Vệ Anh, bị đuổi ra ngoài khi Hàn Lập vào gặp riêng.","anchor":"Lỗ trưởng lão là gia thúc tổ của vãn bối, bất quá vãn bối đối với tiền bối ngưỡng mộ đại danh đã lâu"}],"tuViMoc":[],"nhanMach":[{"ten":"Lỗ Vệ Anh","tag":"ho-hang","quanHe":"Gia thúc tổ.","ghiChu":"@c0800"},{"ten":"Bạch Thư Quân","tag":"dong-hanh","quanHe":"Đồng môn, đi cùng.","ghiChu":"@c0800"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0800"]},{"id":"nu-tu-ao-luc-ham-su-diet","name":"Nữ tử áo lục (Hạm sư điệt)","cn":"","aliases":["Hạm sư điệt"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Nữ tử áo lục cưỡi linh cầm trắng do thám tình hình xung quanh Trụy Ma Cốc, báo cáo cho lão giả trong tiểu cốc và được phái tiếp tục theo dõi Quỷ Linh Môn.","vaiTro":"Do thám viên cho thế lực bí mật theo dõi Quỷ Linh Môn","tinhCach":"Tuân lệnh; nhanh nhẹn","tabs":{"diem":[{"text":"Cưỡi linh cầm trắng do thám Quỷ Linh Môn, là sư điệt được giao nhiệm vụ trinh sát","chuong":"@c0802"}],"kinhLich":[{"mucCt":"vua","text":"Cưỡi linh cầm trắng bay đến tiểu cốc, báo cáo cho lão giả rằng chướng khí đã rút và nhiều tu sĩ đã vào Trụy Ma Cốc, Quỷ Linh Môn phần lớn chưa động thân. Được lão giả phái tiếp tục theo dõi đối phương.","anchor":"Hạm sư điệt, ngươi lại tiếp tục đi theo dõi bọn họ đi","bridge":true,"khoang":"@c0802"}],"tuViMoc":[],"nhanMach":[{"ten":"Lão giả trong tiểu cốc","tag":"su-mon","quanHe":"Sư bá/sư thúc, là người chỉ huy ra lệnh cho nữ tử do thám"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[{"ten":"Linh cầm trắng","trangThai":"dang-co","moTa":"Linh cầm trắng như tuyết, dùng làm tọa kỵ bay đi do thám","nguon":"@c0802"}],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802"]},{"id":"lao-gia-tieu-coc","name":"Lão giả trong tiểu cốc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Lão giả bí ẩn ngồi giữa pháp trận ngũ giác trong tiểu cốc ẩn giấu gần Trụy Ma Cốc, chỉ huy nhóm tu sĩ áo lục theo dõi Quỷ Linh Môn, quyết định chờ đối phương động thân mới hành động.","vaiTro":"Thủ lĩnh thế lực bí mật theo dõi Quỷ Linh Môn tại Trụy Ma Cốc","tinhCach":"Trầm tĩnh; mưu lược; kiên nhẫn chờ thời","tabs":{"diem":[{"text":"Chỉ huy nhóm bí mật trong tiểu cốc, quyết định chờ Quỷ Linh Môn động thân mới ra tay","chuong":"@c0802"}],"kinhLich":[{"mucCt":"vua","text":"Ngồi giữa pháp trận ngũ giác với năm tu sĩ áo lục ở năm đỉnh, nghe Hạm sư điệt báo cáo tình hình. Ra lệnh chờ đợi, bảo nữ tử tiếp tục theo dõi Quỷ Linh Môn.","anchor":"Hừ! Một khi mấy lão quái Quỷ Linh Môn vẫn chưa động thân. Chúng ta cũng không vội","bridge":true,"khoang":"@c0802"}],"tuViMoc":[],"nhanMach":[{"ten":"Nữ tử áo lục (Hạm sư điệt)","tag":"su-mon","quanHe":"Sư điệt, được phái đi do thám Quỷ Linh Môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802"]},{"id":"dao-si-ao-bao-tro","name":"Đạo sĩ áo bào tro","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đạo sĩ năm sáu mươi tuổi sở hữu hai thượng cổ khôi lỗi có sức mạnh sánh tu sĩ Nguyên Anh, tự tin về chuyến đi Trụy Ma Cốc sẽ thu hoạch lớn.","vaiTro":"Tu sĩ sở hữu thượng cổ khôi lỗi mạnh, hướng đến Trụy Ma Cốc đoạt bảo","tinhCach":"Tự đắc; tự tin vào sức mạnh khôi lỗi","tabs":{"diem":[{"text":"Sở hữu cặp thượng cổ khôi lỗi sức mạnh ngang tu sĩ Nguyên Anh, tự đắc về sức chiến đấu","chuong":"@c0802"}],"kinhLich":[{"chuong":"@c0802","importance":"normal","mucCt":"vua","tieuDe":"Mang thượng cổ khôi lỗi hướng đến Trụy Ma Cốc","text":"Đứng trên đỉnh núi cao nhất, phía sau có hai thượng cổ khôi lỗi cao hai trượng. Tự đắc thu khôi lỗi vào tay áo rồi hóa hồng quang bay hướng Trụy Ma Cốc.","anchor":"Được hai thượng cổ khôi lỗi có thể sánh với tu sĩ Nguyên Anh này trợ giúp, chuyến đi Trụy Ma Cốc lần này xem ra thu hoạch sẽ khá"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Thượng cổ khôi lỗi (cặp)","trangThai":"dang-co","moTa":"Hai khôi lỗi cao hai trượng, mặt mũi hung dữ, sức mạnh sánh tu sĩ Nguyên Anh, có thể thu nhỏ vào tay áo","nguon":"@c0802"}]}},"nguon":["@c0802"]},{"id":"truong-lao-yem-nguyet-tong","name":"Trưởng lão Yểm Nguyệt Tông","cn":"","aliases":["Sư tỷ Nam Cung Uyển"],"gioiTinh":"nu","theLuc":[{"ten":"Yểm Nguyệt Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh kỳ","trangThai":"song","blurb":"Nữ trưởng lão Yểm Nguyệt Tông, sắc mặt tái nhợt băng lãnh, là sư tỷ của Nam Cung Uyển. Cùng Lệnh Hồ lão tổ hướng đến Trụy Ma Cốc.","vaiTro":"Trưởng lão Yểm Nguyệt Tông, sư tỷ Nam Cung Uyển","tinhCach":"Băng lãnh; trầm mặc","tabs":{"diem":[{"text":"Sư tỷ của Nam Cung Uyển, trưởng lão Yểm Nguyệt Tông, sắc mặt tái nhợt băng lãnh","chuong":"@c0802"}],"kinhLich":[{"mucCt":"gon","text":"Cùng Lệnh Hồ lão tổ và lão giả lạ mặt song song phi hành hướng Trụy Ma Cốc, sắc mặt buồn bực.","anchor":"bên cạnh hắn là một nữ tử sắc mặt tái nhợt, chính là nữ tử băng lãnh, trưởng lão Yểm Nguyệt Tông sư tỷ của Nam Cung Uyển","bridge":true,"khoang":"@c0802"}],"tuViMoc":[],"nhanMach":[{"ten":"Nam Cung Uyển","tag":"su-mon","quanHe":"Sư muội"},{"ten":"Lệnh Hồ lão tổ","tag":"dong-minh","quanHe":"Cùng phi hành hướng Trụy Ma Cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802"]},{"id":"lao-gia-mat-xech-mieng-to","name":"Lão giả mắt xếch miệng to","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Nguyên Anh kỳ","trangThai":"song","blurb":"Lão giả tướng mạo kỳ lạ, mắt xếch miệng to, đi cùng Lệnh Hồ lão tổ và trưởng lão Yểm Nguyệt Tông hướng đến Trụy Ma Cốc. Hàn Lập không nhận ra.","vaiTro":"Tu sĩ Nguyên Anh lạ mặt đi cùng Lệnh Hồ lão tổ","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tướng mạo kỳ lạ, đi cùng Lệnh Hồ lão tổ và trưởng lão Yểm Nguyệt Tông mà Hàn Lập không nhận ra","chuong":"@c0802"}],"kinhLich":[{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Cùng Lệnh Hồ lão tổ và trưởng lão Yểm Nguyệt Tông song song phi hành hướng Trụy Ma Cốc.","anchor":"bên cạnh hắn là một nữ tử sắc mặt tái nhợt, chính là nữ tử băng lãnh, trưởng lão Yểm Nguyệt Tông sư tỷ của Nam Cung Uyển"}],"tuViMoc":[],"nhanMach":[{"ten":"Lệnh Hồ lão tổ","tag":"dong-minh","quanHe":"Cùng phi hành hướng Trụy Ma Cốc"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802"]},{"id":"trong-than-su","name":"Trọng Thần Sư","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Dẫn đầu hơn mười pháp sĩ Mộ Lan đến Trụy Ma Cốc bằng phi xa hình nón. Tu vi Nguyên Anh hậu kỳ đủ sức chấn nhiếp tu sĩ Thiên Nam muốn trả thù.","anchor":"Lấy tu vi Nguyên Anh hậu kỳ của nho sinh, đích xác thực sự có thể chấn nhiếp những tu sĩ bình thường tìm đến trả thù","bridge":true,"khoang":"@c0802"},{"importance":"bridge","mucCt":"gon","chuong":"@c0803","tieuDe":"Quan sát tại cốc khẩu","text":"Hai tay chắp sau lưng, vẻ mặt bình tĩnh quan sát Ngụy Vô Nhai xuất hiện tại cốc khẩu Trụy Ma Cốc.","anchor":"vị Mộ Lan thần sư này hai tay chắp sau lưng, vẻ mặt bình tĩnh nhìn Ngụy Vô Nhai"},{"mucCt":"vua","text":"Dẫn hơn mười pháp sĩ Mộ Lan vào Truyền Tống Trận, giao Trụy Ma lệnh cho Vương Thiên Thắng. Trước khi đi cảnh cáo Ngụy Vô Nhai rằng truyền tống vị trí ngẫu nhiên, tu sĩ Quỷ Linh Môn tốt nhất không nên gặp bọn họ.","anchor":"Truyền Tống Trận này truyền tống tới vị trí ngẫu nhiên. Nếu như vậy mà nói, tu sĩ quý môn tốt nhất không nên cùng chúng ta gặp nhau","bridge":true,"khoang":"@c0804"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0802","@c0803","@c0804"],"aliases":["nho sinh họ Trọng"]},{"id":"nhac-thuong-su","name":"Nhạc thượng sư","cn":"","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Cùng Trọng Thần Sư dẫn đầu đoàn Mộ Lan đến Trụy Ma Cốc, thu nhỏ phi xa sau khi hạ cánh.","anchor":"Lấy tu vi Nguyên Anh hậu kỳ của nho sinh, đích xác thực sự có thể chấn nhiếp những tu sĩ bình thường tìm đến trả thù"},{"importance":"bridge","mucCt":"gon","chuong":"@c0803","tieuDe":"Ngạc nhiên trước Ngụy Vô Nhai","text":"Thấp giọng bàn bạc với Trọng Thần Sư, lộ vẻ ngạc nhiên khi Ngụy Vô Nhai giáng lâm cốc khẩu.","anchor":"nữ tử họ Nhạc đứng một bên trong mắt lại lộ ra một tia ngạc nhiên"},{"importance":"bridge","mucCt":"gon","chuong":"@c0804","text":"Cùng Trọng Thần Sư dẫn pháp sĩ Mộ Lan vào Truyền Tống Trận.","anchor":"Truyền Tống Trận này truyền tống tới vị trí ngẫu nhiên. Nếu như vậy mà nói, tu sĩ quý môn tốt nhất không nên cùng chúng ta gặp nhau"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0802","@c0803","@c0804"],"aliases":["nữ tử họ Nhạc","nữ tử cầm cổ đăng"]},{"id":"vuong-thien-co","name":"Vương Thiên Cổ","cn":"","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Đứng phía trước bên trái đoàn Quỷ Linh Môn hơn trăm tu sĩ áo đen, là một trong ba tu sĩ Nguyên Anh dẫn đầu.","anchor":"Nhất là người đứng bên trái, Hàn Lập nhận biết rất rõ ràng, đúng là vị Quỷ Linh Môn Vương Thiên Cổ"},{"mucCt":"vua","text":"Giám sát bố trí Đan Hướng Truyền Tống Trận tại cốc khẩu. Cẩn thận lấy ra linh thạch bậc cao kim hoàng sắc từ hộp ngọc đặt vào trung tâm pháp trận, bộ dáng cung kính khi nói chuyện với Vương Thiên Thắng.","anchor":"Hắn cẩn thận đem hộp ngọc mở ra, trong hộp lộ ra một khối linh thạch kim hoàng sắc","bridge":true,"khoang":"@c0803"},{"mucCt":"vua","text":"Dẫn bảy tám Kết Đan tu sĩ Quỷ Linh Môn lục tục truyền tống. Sắc mặt đại biến khi thấy Đông Môn Đồ mang theo năm Nguyên Anh tu sĩ (Ngũ Hành Linh Anh) tới.","anchor":"Vương Thiên Cổ nguyên sắc mặt vẫn thong dong, vừa thấy Đông Môn Đồ mang theo năm tên Nguyên Anh tu sĩ đi tới thì sắc mặt rốt cục đại biến","bridge":true,"khoang":"@c0804"},{"chuong":"@c0812","importance":"bridge","mucCt":"gon","text":"Được nhắc đến là vị đứng đầu Quỷ Linh Môn nhưng không có mặt cùng nhóm lão giả họ Chung tại thung lũng băng tuyết, gợi ý đang hoạt động riêng.","anchor":"vị đứng đầu Quỷ Linh Môn là Vương Thiên Cổ lại không thấy đâu"},{"chuong":"@c0822","importance":"bridge","mucCt":"vua","text":"Cùng đoàn Quỷ Linh Môn leo hắc sơn thạch tiến về Linh Miểu Viên, than phương viên hơn trăm dặm đều cấm chế không thể phi hành, cho biết dọc đường đã mất ba đệ tử.","anchor":"Dọc theo đường đi chúng ta đã mất ba tên đệ tử"}],"nhanMach":[{"ten":"Vương Thiên Thắng","tag":"cap-tren","quanHe":"Tông chủ Quỷ Linh Môn, Vương Thiên Cổ tỏ thái độ cung kính","ghiChu":"@c0803"}],"tuViMoc":[]},"nguon":["@c0802","@c0803","@c0804","@c0812","@c0822"]},{"id":"vuong-thien-thang","name":"Vương Thiên Thắng","cn":"王天胜","aliases":["tu sĩ hắc bào rộng","trung niên tu sĩ sắc mặt âm lệ","hắc bào rộng"],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh","trangThai":"song","blurb":"Tu sĩ Nguyên Anh Quỷ Linh Môn, mặc hắc bào rộng, sắc mặt âm lệ, khí thế bất phàm. Đứng ở giữa ba tu sĩ Nguyên Anh dẫn đầu Quỷ Linh Môn, là hạng thường xuyên nắm quyền ra lệnh. Mặt lạ, không tham gia chiến tranh biên giới Thiên Nam.","vaiTro":"Tu sĩ Nguyên Anh Quỷ Linh Môn, đứng giữa dẫn đầu đoàn","tinhCach":"Âm lệ; uy quyền","tabs":{"diem":[{"text":"Đứng ở giữa ba tu sĩ Nguyên Anh dẫn đầu Quỷ Linh Môn, khí thế bất phàm, là hạng nắm quyền ra lệnh","chuong":"@c0802"},{"text":"Tông chủ Quỷ Linh Môn, tu vi Nguyên Anh, sắc mặt âm lệ","chuong":"@c0803"},{"text":"Hợp tác cùng đại trưởng lão Cửu Quốc Minh Ngụy Vô Nhai để mở Trụy Ma Cốc","chuong":"@c0803"}],"kinhLich":[{"mucCt":"vua","text":"Đứng ở giữa ba tu sĩ Nguyên Anh dẫn đầu hơn trăm tu sĩ áo đen Quỷ Linh Môn đến lối vào Trụy Ma Cốc. Sắc mặt âm lệ, khí thế bất phàm, mặt lạ không tham gia chiến tranh biên giới trước đó.","anchor":"Nhất là người đứng bên trái, Hàn Lập nhận biết rất rõ ràng, đúng là vị Quỷ Linh Môn Vương Thiên Cổ","bridge":true,"khoang":"@c0802"},{"importance":"normal","mucCt":"ky","chuong":"@c0803","tieuDe":"Lộ danh tính tông chủ, tuyên bố quy tắc nhập cốc","text":"Tự xưng danh Vương Thiên Thắng, xác nhận là tông chủ Quỷ Linh Môn. Nghênh đón Ngụy Vô Nhai tại cốc khẩu. Tuyên bố pháp trận Đan Hướng Truyền Tống Trận là đặc chế, đơn hướng truyền tống vào Trụy Ma Cốc, vị trí đích không cố định, có xác suất nhỏ rơi vào khe hở không gian. Chỉ ai có Trụy ma lệnh mới được dùng, không phân biệt chính ma. Quỷ Linh Môn sẽ vào cuối cùng rồi hủy pháp trận. Giải đáp rằng trong Trụy Ma Cốc có thượng cổ Truyền Tống Trận hoàn hảo để xuất cốc rất đơn giản.","anchor":"Tại hạ là Quỷ Linh Môn Vương Thiên Thắng đồng thời là tông chủ Quỷ Linh Môn"},{"mucCt":"vua","text":"Chỉ huy toàn bộ Truyền Tống Trận vào Trụy Ma Cốc, cho Vương Thiền cùng trưởng lão đi trước thị phạm. Hỏi Đông Môn Đồ về năm tu sĩ lục bào nhưng bị lảng tránh. Nghe Ngụy Vô Nhai gọi tên Hàn Lập, nhận ra danh tính, hồi tưởng quá khứ Vương Thiền từng bắt được rồi để mất, nay đối phương đã thành Nguyên Anh danh tiếng chỉ thấp hơn tam đại tu sĩ, trong lòng kiêng kỵ.","anchor":"Tên Hàn Lập hắn từ nhiều năm trước đã nghe nói qua","bridge":true,"khoang":"@c0804"}],"tuViMoc":[{"chuong":"@c0803","canhGioi":"Nguyên Anh","text":"Tu vi Nguyên Anh, được xác nhận qua thân phận tông chủ Quỷ Linh Môn.","importance":"major"}],"nhanMach":[{"ten":"Vương Thiên Cổ","tag":"dong-minh","quanHe":"Cùng dẫn đầu Quỷ Linh Môn, đứng bên trái"},{"ten":"Vương Thiền","tag":"ho-hang","quanHe":"Thiếu chủ Quỷ Linh Môn, cùng đoàn"},{"ten":"Ngụy Vô Nhai","tag":"dong-minh","quanHe":"Đối tác hợp tác mở Trụy Ma Cốc, gọi nhau bằng huynh","ghiChu":"@c0803"},{"ten":"Vương Thiên Cổ","tag":"ho-hang","quanHe":"Cùng họ Vương trong Quỷ Linh Môn, Vương Thiên Cổ tỏ thái độ cung kính","ghiChu":"@c0803"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802","@c0803","@c0804"]},{"id":"lao-gia-mat-chim-ung","name":"Lão giả mắt chim ưng","cn":"","aliases":["Lão giả râu tóc bạc trắng mắt chim ưng"],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh Trung Kỳ","trangThai":"song","blurb":"Lão giả Quỷ Linh Môn, khuôn mặt tái nhợt, râu tóc bạc trắng, mắt chim ưng tinh quang bắn tứ phía, tràn ngập sát khí nồng đậm. Tu vi Nguyên Anh Trung Kỳ, mặt lạ không tham gia chiến tranh biên giới Thiên Nam. Hàn Lập đặc biệt chú ý.","vaiTro":"Tu sĩ Nguyên Anh Trung Kỳ của Quỷ Linh Môn","tinhCach":"Đầy sát khí; nguy hiểm","tabs":{"diem":[{"text":"Tu vi Nguyên Anh Trung Kỳ, mắt chim ưng đầy sát khí, Hàn Lập đặc biệt để mắt","chuong":"@c0802"}],"kinhLich":[{"mucCt":"vua","text":"Đứng bên phải ba tu sĩ Nguyên Anh dẫn đầu hơn trăm tu sĩ Quỷ Linh Môn. Khuôn mặt tái nhợt, tinh quang bắn tứ phía, tràn ngập sát khí nồng đậm. Tu vi Nguyên Anh Trung Kỳ khiến Hàn Lập đặc biệt để mắt.","anchor":"Nhưng tu vi lão giả đã là Nguyên Anh Trung Kỳ, điều này làm cho Hàn Lập để mắt nhiều hơn một tí","bridge":true,"khoang":"@c0802"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Thiên Cổ","tag":"dong-minh","quanHe":"Cùng dẫn đầu Quỷ Linh Môn"},{"ten":"Vương Thiên Thắng","tag":"dong-minh","quanHe":"Cùng dẫn đầu Quỷ Linh Môn, đứng ở giữa"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0802"]},{"id":"vuong-thien","name":"Vương Thiền","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Xuất hiện cùng đoàn Quỷ Linh Môn tại lối vào Trụy Ma Cốc, thoạt nhìn tay chân đầy đủ dường bình thường.","anchor":"Vương Thiền thoạt nhìn tay chân đủ hết, tựa hồ hết thảy đều bình thường"},{"importance":"bridge","mucCt":"gon","chuong":"@c0804","text":"Cùng Yến Như Yên và lão giả Nguyên Anh Trung Kỳ đi trước vào Truyền Tống Trận làm tiên phong cho Quỷ Linh Môn.","anchor":"Vương Thiền mang theo mặt nạ màu bạc cùng Yến Như Yên không nói gì đi tới pháp trận"},{"chuong":"@c0812","importance":"bridge","mucCt":"gon","text":"Có mặt trong nhóm đệ tử Quỷ Linh Môn, theo lão giả họ Chung tiến vào khe băng trong Trụy Ma Cốc.","anchor":"Trong số đệ tử này có Vương Thiền cùng Yến Như Yên"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0802","@c0804","@c0806","@c0812"],"aliases":["Thiếu chủ Quỷ Linh Môn","mặt nạ bạc","mặt nạ quỷ bạc"]},{"id":"yen-nhu-yen","name":"Yến Như Yên","cn":"","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c0802","importance":"bridge","mucCt":"gon","text":"Đứng bên cạnh Vương Thiền trong đoàn Quỷ Linh Môn, thần sắc không tốt, có chút tiều tụy.","anchor":"Mà Yến Như Yên đứng một bên, thần sắc tựa hồ không quá tốt, có chút tiều tụy"},{"importance":"bridge","mucCt":"gon","chuong":"@c0804","text":"Cùng Vương Thiền đi trước vào Truyền Tống Trận.","anchor":"Vương Thiền mang theo mặt nạ màu bạc cùng Yến Như Yên không nói gì đi tới pháp trận"},{"chuong":"@c0812","importance":"bridge","mucCt":"gon","text":"Có mặt trong nhóm đệ tử Quỷ Linh Môn, theo lão giả họ Chung tiến vào khe băng có bạch quang trong Trụy Ma Cốc.","anchor":"Trong số đệ tử này có Vương Thiền cùng Yến Như Yên"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0802","@c0804","@c0806","@c0812"]},{"id":"nguy-vo-nhai","name":"Ngụy Vô Nhai","tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện ngoạn mục trên bầu trời cốc khẩu dưới dạng bạch hồng chói mắt, được trung niên tu sĩ Quỷ Linh Môn (Vương Thiên Thắng) nghênh đón. Lạnh lùng cảnh cáo nếu trong cốc không có kiện đồ vật đã hẹn ước thì sẽ trở mặt.","anchor":"Nếu trong cốc không có kiện đồ vật mà ngươi đã nói thì đừng trách Ngụy mỗ đến lúc đó trở mặt không nhận thân","bridge":true,"khoang":"@c0803"},{"mucCt":"vua","text":"Quan sát nho sinh họ Trọng với vẻ đăm chiêu. Chủ động tới trước mặt Hàn Lập khuyên không nên vào nơi phong hiểm, bị từ chối thì thần sắc âm trầm, nói hy vọng quan điểm hai người không giống nhau rồi rút đi.","anchor":"Ngụy Vô Nhai cuối cùng nói như thế rồi thân hình chớp lên, một lần nữa trở lại vị trí ban đầu","bridge":true,"khoang":"@c0804"},{"chuong":"@c0814","importance":"bridge","mucCt":"gon","text":"Được Lỗ Vệ Anh nhắc tới khi bàn về Thập Tuyệt độc: chủ tu độc công, có thể sinh ra Phúc Thi chi độc khiến tu sĩ khác không dám tiếp cận trong mười trượng.","anchor":"Ngụy Vô Nhai chủ tu độc công, có thể sinh ra Phúc Thi chi độc"},{"mucCt":"ky","text":"Cùng môn chủ Quỷ Linh Môn và Vương Thiên Cổ tiến về Linh Miểu Viên. Nghi ngờ truyền thuyết Linh Miểu Viên là lời đồn Thượng cổ tu sĩ truyền ra. Được hứa chia bảo vật đổi lấy việc mượn danh chấn trụ tu sĩ khác vào cốc. Ngoài mặt gật đầu nhưng trong lòng cười lạnh không tin nửa phần. Chất vấn tung tích Chung trưởng lão.","anchor":"hắn tuyệt không tin tưởng nửa phần","bridge":true,"khoang":"@c0822"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c0803","@c0804","@c0814","@c0822"],"trangThai":"song","gioiTinh":"nam"},{"id":"lao-gia-sat-khi","name":"Lão giả có sát khí dày đặc","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh","trangThai":"song","blurb":"Tu sĩ Nguyên Anh thứ ba bên Quỷ Linh Môn, sát khí dày đặc. Đứng cùng Vương Thiên Thắng và Vương Thiên Cổ tại cốc khẩu Trụy Ma Cốc.","vaiTro":"Tu sĩ Nguyên Anh thứ ba bên Quỷ Linh Môn","tinhCach":"Trầm tĩnh, thần sắc không thay đổi trước linh thạch bậc cao","tabs":{"diem":[{"text":"Tu sĩ Nguyên Anh thứ ba của Quỷ Linh Môn, sát khí dày đặc, thần sắc bình thản","chuong":"@c0803"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0803","tieuDe":"Xuất hiện tại cốc khẩu","text":"Đứng cùng Vương Thiên Thắng và Vương Thiên Cổ tại cốc khẩu, thần sắc không thay đổi khi linh thạch bậc cao được lấy ra.","anchor":"Hắn cẩn thận đem hộp ngọc mở ra, trong hộp lộ ra một khối linh thạch kim hoàng sắc"}],"tuViMoc":[{"chuong":"@c0803","canhGioi":"Nguyên Anh","text":"Tu vi Nguyên Anh, là tu sĩ Nguyên Anh thứ ba của Quỷ Linh Môn (ngoài Toái Hồn Chân Nhân và Vương Thiên Thắng).","importance":"major"}],"nhanMach":[{"ten":"Vương Thiên Thắng","tag":"cap-tren","quanHe":"Tông chủ Quỷ Linh Môn","ghiChu":"@c0803"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0803"]},{"id":"dong-mon-do","name":"Đông Môn Đồ","aliases":["Ngự Linh Tông đại trưởng lão","Lục bào lão giả"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Dẫn sáu người gồm bản thân và Ngũ Hành Linh Anh (năm Nguyên Anh Sơ Kỳ mặc lục bào) tới Truyền Tống Trận. Bị Vương Thiên Thắng hỏi danh tính năm tu sĩ nhưng lảng tránh. Phát hiện linh anh trên người Hàn Lập phản ứng, liếc Hàn Lập với ánh mắt tràn ngập ý bất thiện trước khi truyền tống đi.","anchor":"Đông Môn Đồ trong nháy mắt truyền đi lại lơ đãng nhìn Hàn Lập liếc mắt một cái. Trong ánh mắt tràn ngập ý bất thiện","bridge":true,"khoang":"@c0804"},{"mucCt":"vua","text":"Dẫn năm tu sĩ Nguyên Anh Kỳ áo xanh lá cây đến trước hạp cốc, chủ động đề nghị Thiên Tinh Chân Nhân liên thủ phá cấm chế. Thuyết phục bằng lý lẽ chỉ hợp tác phá trận rồi vào nội cốc tách ra, tự nhận ở Ngự Linh Tông đã lâu và có nghiên cứu trận pháp.","anchor":"Tại hạ mặc dù ở Ngự Linh Tông đã lâu, ít khi cùng người khác gặp gỡ","bridge":true,"khoang":"@c0812"},{"mucCt":"ky","text":"Dẫn năm tu sĩ Ngự Linh Tông ra khỏi hạp cốc sau khi cùng Thiên Tinh phá cấm chế. Đề nghị tiếp tục liên thủ tầm bảo bị Thiên Tinh từ chối. Ngoài mặt chúc phúc nhưng âm trầm tiếc không có được hai con Khôi Lỗi. Vỗ túi linh thú thả ra đám biên bức ngân quang, bắn ra viên dược hoàn đen cho chúng nuốt rồi bay theo phương hướng khác để truy tung Thiên Tinh, hóa lục quang dẫn năm tu sĩ bay theo.","anchor":"thì liền vỗ túi linh thú bên hông","bridge":true,"khoang":"@c0822"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0804","@c0812","@c0822"]},{"id":"lao-gia-nguyen-anh-trung-ky","name":"Lão giả Nguyên Anh Trung Kỳ","gioiTinh":"nam","canhGioiCaoNhat":"Nguyên Anh Trung Kỳ","trangThai":"song","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"vaiTro":"Trưởng lão Quỷ Linh Môn, đi tiên phong vào Trụy Ma Cốc","tinhCach":"Điềm tĩnh, mặt không biến sắc trước hiểm nguy","blurb":"Lão giả tu vi Nguyên Anh Trung Kỳ thuộc Quỷ Linh Môn, cùng Vương Thiền và Yến Như Yên đi trước vào Truyền Tống Trận làm tiên phong.","tabs":{"diem":[{"text":"Điềm tĩnh không chút thay đổi khi đi tiên phong vào Trụy Ma Cốc","chuong":"@c0804"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0804","text":"Cùng Vương Thiền và Yến Như Yên đi trước vào Truyền Tống Trận làm tiên phong cho Quỷ Linh Môn, mặt không chút thay đổi.","anchor":"lão giả Nguyên Anh Trung Kỳ một bên mặt cũng không chút thay đổi cùng nhau đi vào"}],"tuViMoc":[{"chuong":"@c0804","canhGioi":"Nguyên Anh Trung Kỳ","text":"Được giới thiệu là lão giả tu vi Nguyên Anh Trung Kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Thiền","tag":"dong-hanh","quanHe":"Cùng đi tiên phong vào Trụy Ma Cốc"}],"tuiDo":{}},"nguon":["@c0804"]},{"id":"trinh-su-huynh","name":"Trình sư huynh","aliases":["lão giả tóc bạc họ Trình"],"gioiTinh":"nam","trangThai":"song","theLuc":[],"vaiTro":"Sư huynh của Hàn Lập, lão giả gần hết thọ nguyên","tinhCach":"Kiên trì tu luyện dù thọ nguyên sắp cạn","blurb":"Lão giả tóc bạc là sư huynh của Hàn Lập, gần hết thọ nguyên nhưng vẫn vào Trụy Ma Cốc tìm cơ duyên.","tabs":{"diem":[{"text":"Gần hết thọ nguyên vẫn liều mình vào Trụy Ma Cốc","chuong":"@c0804"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c0804","text":"Cùng hai lão giả khác (đều gần hết thọ nguyên) vào Truyền Tống Trận, Hàn Lập nhận ra và thở dài.","anchor":"Người này chính là là lão giả tóc bạc, vị Trình sư huynh kia của hắn"}],"tuViMoc":[],"nhanMach":[{"ten":"Hàn Lập","tag":"su-mon","quanHe":"Sư đệ, Hàn Lập nhận ra và cười khổ thở dài"}],"tuiDo":{}},"nguon":["@c0804"]},{"id":"lao-gia-map-map","name":"Lão giả mập mạp","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Tu sĩ béo phì trong Trụy Ma Cốc, phát hiện khe hở không gian nhỏ nhưng bị khe hở vô hình khác bất ngờ phân thây chết ngay tại chỗ.","vaiTro":"Tu sĩ vô danh bị khe hở không gian giết chết trong ngoại cốc Trụy Ma Cốc","tinhCach":"Cẩn thận nhưng không đủ đề phòng","tabs":{"diem":[{"text":"Bị khe hở không gian vô hình phân thây chết ngay trong ngoại cốc, minh chứng cho sự nguy hiểm khắp nơi của Trụy Ma Cốc.","chuong":"@c0805"}],"kinhLich":[{"mucCt":"vua","text":"Phát hiện khe hở không gian nhỏ cỡ một thước, tự nhủ cẩn thận. Khi vừa dùng độn quang bay đi năm sáu trượng thì bị khe hở không gian vô hình bất ngờ phân thây thành hai đoạn, chết ngay tại chỗ không kịp kêu.","anchor":"Lão giả ngay cả tiếng kêu thảm thiết cũng không có kịp phát ra","bridge":true,"khoang":"@c0805"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0805"]},{"id":"dai-han-mat-dao","name":"Đại hán mặt đao","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong ba tu sĩ cẩm bào bị truyền tống vào cấm chế trong ngoại cốc Trụy Ma Cốc. Chửi mắng Quỷ Linh Môn, sở hữu pháp bảo thạch ấn tứ phương, dẫn đầu hợp lực phá cấm chế.","vaiTro":"Tu sĩ cẩm bào bị mắc kẹt trong cấm chế ngoại cốc","tinhCach":"Nóng nảy, hay chửi mắng; quyết đoán khi hành động","tabs":{"diem":[{"text":"Chửi mắng Quỷ Linh Môn khi bị truyền tống vào cấm chế, dùng thạch ấn tứ phương dẫn đầu phá chế.","chuong":"@c0805"}],"kinhLich":[{"chuong":"@c0805","importance":"normal","mucCt":"vua","tieuDe":"Bị mắc kẹt trong cấm chế ngoại cốc","text":"Bị truyền tống vào cấm chế bảy sắc thái hà trong đống loạn thạch, không ra được quá mười trượng. Chửi mắng Quỷ Linh Môn, phun ra thạch ấn tứ phương phóng to cỡ một thước, hợp lực với hai đồng bạn phá cấm chế.","anchor":"Đám Quỷ Linh Môn hỗn đản dĩ nhiên đem ba người chúng ta truyền tống đến cấm chế này"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Thạch ấn tứ phương","trangThai":"dang-co","moTa":"Pháp bảo công kích, tứ phương hình, hoàng quang, có thể phóng to.","nguon":"@c0805"}]}},"nguon":["@c0805"]},{"id":"tu-si-go-ma-cao","name":"Tu sĩ gò má cao","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong ba tu sĩ cẩm bào bị mắc kẹt trong cấm chế ngoại cốc Trụy Ma Cốc, phân tích lạnh lùng tình hình và phụ trợ phá chế bằng phi kiếm.","vaiTro":"Tu sĩ cẩm bào bị mắc kẹt trong cấm chế ngoại cốc","tinhCach":"Lạnh lùng, sắc bén trong phân tích","tabs":{"diem":[{"text":"Phân tích cấm chế không phải loại công kích, đề nghị dùng pháp lực bài trừ.","chuong":"@c0805"}],"kinhLich":[{"chuong":"@c0805","importance":"bridge","mucCt":"gon","text":"Bị truyền tống vào cấm chế bảy sắc thái hà, phân tích tình hình và dùng phi kiếm phụ trợ phá cấm chế.","anchor":"cấm chế ở ngoại cốc có lợi hại cũng quá lợi hại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0805"]},{"id":"tu-si-dien-muc-ngam-den","name":"Tu sĩ diện mục ngăm đen","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong ba tu sĩ cẩm bào bị mắc kẹt trong cấm chế ngoại cốc Trụy Ma Cốc, đồng ý hợp lực phá chế và dùng phi kiếm phụ trợ.","vaiTro":"Tu sĩ cẩm bào bị mắc kẹt trong cấm chế ngoại cốc","tinhCach":"Ít nói, hợp tác","tabs":{"diem":[{"text":"Đồng ý kế hoạch phá cấm chế, phụ trợ bằng phi kiếm cùng hai đồng bạn.","chuong":"@c0805"}],"kinhLich":[{"chuong":"@c0805","importance":"bridge","mucCt":"gon","text":"Bị truyền tống vào cấm chế, dùng phi kiếm phụ trợ hợp lực phá chế.","anchor":"Hai người ta ở một bên phụ trợ"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0805"]},{"id":"chung-truong-lao","name":"Chung trưởng lão","cn":"","aliases":["Lão giả họ Chung"],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh","trangThai":"song","blurb":"Trưởng lão Quỷ Linh Môn, lão giả mặt tái nhợt. Tại Trụy Ma Cốc chỉ huy đệ tử tìm kiếm đại thụ chứa âm khí đen, xác nhận đúng mục tiêu của môn phái.","vaiTro":"Trưởng lão Quỷ Linh Môn, chỉ huy nhóm tìm kiếm tại Trụy Ma Cốc","tinhCach":"Chỉ huy quyết đoán; thưởng phạt phân minh","tabs":{"diem":[{"text":"Lão giả mặt tái nhợt, trưởng lão Quỷ Linh Môn, chỉ huy nhóm đệ tử tìm được đại thụ chứa âm khí mục tiêu tại Trụy Ma Cốc.","chuong":"@c0806"},{"text":"Dùng ngón tay rút âm khí đen từ đại thụ hình người khổng lồ, xác nhận đúng mục tiêu Quỷ Linh Môn cần tìm tại Trụy Ma Cốc.","chuong":"@c0806"}],"kinhLich":[{"chuong":"@c0806","importance":"normal","mucCt":"vua","tieuDe":"Tìm được đại thụ chứa âm khí tại Trụy Ma Cốc","text":"Phiêu phù trên không chỉ huy sáu đệ tử hắc y tìm kiếm trong rừng. Khi đệ tử phát hiện đại thụ hình người khổng lồ, xuống kiểm tra, rút một tia âm khí màu đen từ thân cây xác nhận đúng mục tiêu, hứa trọng thưởng và sai gọi người khác tới.","anchor":"Quả thật là nơi này. Gọi những người khác lại đây."},{"mucCt":"vua","text":"Tự ra tay dùng âm khí hóa hai con Mặc Giao kết hợp cự võng lửa tiêu diệt bích hổ cổ thú tại thung lũng băng tuyết. Dưới thi thể cổ thú lộ ra khe băng có bạch quang, dẫn đám đệ tử bay vào.","anchor":"hai tay hắn bắt quyết, vô số luồng khí đen nhánh như mực từ trên người toát ra","bridge":true,"khoang":"@c0812"},{"chuong":"@c0822","importance":"bridge","mucCt":"gon","text":"Được tiết lộ đang ở chỗ bí mật khác trong nội cốc tìm bảo vật trân hi, phiêu phù trên đống loạn thạch sai đệ tử tìm dấu hiệu đặc biệt.","anchor":"Chung trưởng lão kỳ thật đi tới một chỗ bí mật khác"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Thiền","tag":"cap-tren","quanHe":"Thiếu chủ Quỷ Linh Môn","ghiChu":"Cùng hoạt động tại Trụy Ma Cốc"},{"ten":"Vương Thiên Cổ","tag":"cap-tren","quanHe":"Tông chủ Quỷ Linh Môn","ghiChu":"Không có mặt cùng Chung trưởng lão, đi nơi khác"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0806","@c0812","@c0822"]},{"id":"lao-gia-toc-bac-ho-trinh","name":"Lão giả tóc bạc họ Trình","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lạc Vân Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh Kỳ","trangThai":"song","blurb":"Lão giả Nguyên Anh thuộc Lạc Vân Tông, sư huynh của Vương Thiên Cổ. Tại Trụy Ma Cốc cảm ứng được Tử Linh ẩn dưới rừng nhưng không truy cứu.","vaiTro":"Tu sĩ Nguyên Anh Lạc Vân Tông, sư huynh Vương Thiên Cổ","tinhCach":"Điềm tĩnh, không nhiều chuyện","tabs":{"diem":[{"text":"Tu sĩ Nguyên Anh Lạc Vân Tông, sư huynh Vương Thiên Cổ, cảm ứng được Tử Linh ẩn thân nhưng bỏ qua.","chuong":"@c0806"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c0806","canhGioi":"Nguyên Anh Kỳ","text":"Lão giả Nguyên Anh thuộc Lạc Vân Tông.","importance":"major"}],"nhanMach":[{"ten":"Vương Thiên Cổ","tag":"su-mon","quanHe":"Sư đệ tại Lạc Vân Tông","ghiChu":"Tử Linh nhận ra mối liên hệ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0806"]},{"id":"tu-bao-lao-gia-ho-lam","name":"Tử bào lão giả họ Lâm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Nguyên Anh Kỳ","trangThai":"song","blurb":"Lão giả Nguyên Anh mặc tử bào, mặt đầy nếp nhăn. Cùng hai lão giả khác bay qua rừng tại Trụy Ma Cốc, muốn kiểm tra khu rừng nhưng bị can ngăn.","vaiTro":"Tu sĩ Nguyên Anh tại Trụy Ma Cốc","tinhCach":"Tò mò, dễ bị lợi ích kích thích","tabs":{"diem":[{"text":"Lão giả Nguyên Anh mặc tử bào, muốn kiểm tra khu rừng Tử Linh ẩn thân nhưng bị đồng hành can ngăn.","chuong":"@c0806"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c0806","canhGioi":"Nguyên Anh Kỳ","text":"Lão giả Nguyên Anh mặc tử bào.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0806"]},{"id":"tu-si-ho-au","name":"Tu sĩ họ Âu","cn":"","aliases":["Âu huynh"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Nguyên Anh Kỳ","trangThai":"song","blurb":"Lão giả Nguyên Anh mặt có lồng khí màu xanh bao phủ. Tại Trụy Ma Cốc khuyên đồng hành không nên nhiều chuyện, tập trung tầm bảo.","vaiTro":"Tu sĩ Nguyên Anh tại Trụy Ma Cốc","tinhCach":"Thận trọng, thực tế","tabs":{"diem":[{"text":"Lão giả Nguyên Anh mặt có khí xanh, khuyên đồng hành không nên nhiều chuyện, tập trung tầm bảo.","chuong":"@c0806"}],"kinhLich":[],"tuViMoc":[{"chuong":"@c0806","canhGioi":"Nguyên Anh Kỳ","text":"Lão giả Nguyên Anh mặt có khí xanh.","importance":"major"}],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0806"]},{"id":"hoang-thien-minh","name":"Hoàng Thiên Minh","cn":"黄天明","aliases":["hán tử gầy gò"],"gioiTinh":"nam","theLuc":[{"ten":"Chính đạo liên minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Kết Đan kỳ","trangThai":"tu-vong","blurb":"Tu sĩ Kết Đan kỳ thuộc tiểu tông môn trong chính đạo liên minh, dùng thượng cổ ẩn hình phù ẩn nặc theo dõi ba Nguyên Anh tu sĩ tại Trụy Ma Cốc, bị phát hiện và giết chết.","vaiTro":"Tu sĩ gián điệp, bị diệt khẩu tại Trụy Ma Cốc","tinhCach":"Liều lĩnh, dám theo dõi ba tu sĩ Nguyên Anh dù chỉ ở Kết Đan kỳ","tabs":{"diem":[{"text":"Sở hữu thượng cổ ẩn hình phù hiếm có nhưng vẫn bị Hàn Lập dùng linh nhãn nhìn thấu.","chuong":"@c0808"},{"text":"Sở hữu thượng cổ ẩn hình phù giúp ẩn thân thần diệu, dám truy tung ba tu sĩ Nguyên Anh nhưng bị Hàn Lập dùng linh nhãn nhìn thấu","chuong":"@c0808"},{"text":"Hán tử gầy gò ngoài bốn mươi tuổi, tu sĩ Kết Đan kỳ dùng thượng cổ ẩn hình phù theo dõi ba Nguyên Anh tu sĩ, bị Hàn Lập phát hiện và Lỗ Vệ Anh giết chết diệt khẩu","chuong":"@c0808"}],"kinhLich":[{"chuong":"@c0808","importance":"normal","mucCt":"gon","tieuDe":"Bị phát hiện và giết tại thông đạo Trụy Ma Cốc","text":"Dùng thượng cổ ẩn hình phù ẩn nặc theo dõi ba tu sĩ Nguyên Anh tại thông đạo nội cốc, bị Hàn Lập dùng linh nhãn phát hiện và bắn kiếm khí ép hiện hình, sau đó bị Lỗ Vệ Anh dùng Cự Phong Kỳ băm nát diệt khẩu.","anchor":"Một gã tiểu tiểu nhân Kết Đan Tu Sĩ mà dĩ nhiên dám can đảm truy tung chúng ta"}],"tuViMoc":[{"chuong":"@c0808","canhGioi":"Kết Đan kỳ","text":"Khi xuất hiện đã ở cảnh giới Kết Đan kỳ.","importance":"major"}],"nhanMach":[{"ten":"Hàn Lập","tag":"doi-thu","quanHe":"Người phát hiện hắn ẩn nặc","ghiChu":"Bị Hàn Lập dùng linh nhãn nhìn thấu ẩn hình phù"},{"ten":"Lỗ Vệ Anh","tag":"doi-thu","quanHe":"Người ra tay giết hắn","ghiChu":"Bị Cự Phong Kỳ băm nát diệt khẩu"},{"ten":"Nam Lũng Hầu","tag":"doi-thu","quanHe":"Một trong ba tu sĩ Nguyên Anh bị hắn bám theo","ghiChu":"@c0808"}],"tuiDo":{"phapBao":[{"ten":"Thượng cổ ẩn hình phù","trangThai":"mat","moTa":"Ngọc phù kim sắc thượng cổ giúp ẩn thân thần diệu, sau khi chết bị Lỗ Vệ Anh thu.","nguon":"@c0808"},{"ten":"Cự thuẫn quỷ dị","trangThai":"hong","moTa":"Thuẫn bài bị cơn lốc Cự Phong Kỳ phá vỡ tan tành.","nguon":"@c0808"}]}},"nguon":["@c0808"]},{"id":"tu-linh","name":"Tử Linh","aliases":["Tử Linh Tiên Tử"],"gioiTinh":"nữ","tabs":{"kinhLich":[{"chuong":"@c0812","importance":"normal","mucCt":"ky","tieuDe":"Bí mật theo dấu Quỷ Linh Môn bằng tiêu ký","text":"Một mình ở rừng sâu nơi Quỷ Linh Môn từng tập kết, dùng viên đạn trắng phá đất tìm được tiêu ký (rễ cây cháy đen). Nhận định Quỷ Linh Môn người đông thế mạnh tìm kiếm dễ hơn nhưng không ngờ có người khác biết tiêu ký. Dán lá phù xanh ẩn vào thân cây đại thụ đánh dấu vị trí rồi bay đi theo hướng riêng.","anchor":"Đúng là nơi này rồi. Quỷ Linh Môn người đông thế mạnh, tìm kiếm so với ta dễ dàng hơn nhiều"}]},"nguon":["@c0812"]},{"id":"thien-tinh-chan-nhan","name":"Thiên Tinh Chân Nhân","gioiTinh":"nam","tabs":{"kinhLich":[{"mucCt":"vua","text":"Đứng trước hạp cốc lớn trầm ngâm trước cấm chế nhiều màu, phía sau có hai con Khôi lỗi thượng cổ thực lực Nguyên Anh Sơ Kỳ (luyện từ Hồn Thạch giao dịch với Hàn Lập). Sau khi Đông Môn Đồ (Ngự Linh Tông) đến đề nghị, đồng ý liên thủ phá trận với điều kiện vào nội cốc rồi ai nấy tự lo.","anchor":"Hai ác quỷ Khôi lỗi thời thượng cổ phía sau cũng là do lợi dụng Hồn Thạch mới luyện chế thành","bridge":true,"khoang":"@c0812"},{"chuong":"@c0822","importance":"normal","mucCt":"ky","tieuDe":"Phá cấm hạp cốc cùng Đông Môn Đồ rồi chia tay","text":"Cùng Đông Môn Đồ và năm tu sĩ Ngự Linh Tông phá cấm chế hạp cốc ra khỏi cốc khẩu. Cảnh giác Đông Môn Đồ, cố ý lùi lại tạo khoảng cách, hai con Khôi Lỗi đứng phía sau bảo vệ. Từ chối đề nghị tiếp tục liên thủ tầm bảo, viện cớ thích độc lai độc vãng rồi mang hai con Khôi Lỗi rời đi.","anchor":"bần đạo hay thích độc lai độc vãng"}]},"nguon":["@c0812","@c0822"]},{"id":"thuong-khon-thuong-nhan","name":"Thương Khôn Thượng Nhân","tabs":{"kinhLich":[{"chuong":"@c0814","importance":"bridge","mucCt":"gon","text":"Được nhắc là người năm đó đi qua con đường khe hở không gian nhờ thần thông cảm ứng, đã chuẩn bị kỹ lưỡng cho mỗi bước tìm bảo trong Trụy Ma Cốc kể cả bình Bích Cưu đối phó Tử Vân hạt.","anchor":"Thương Khôn thượng nhân đã tiêu tốn nhiều tâm huyết để chuẩn bị kỹ càng cho mỗi một bước tìm bảo vật trong Trụy Ma Cốc"},{"importance":"bridge","mucCt":"gon","chuong":"@c0815","tieuDe":"Nhắc lại lời về sào huyệt Hỏa Thiềm thú","text":"Được Nam Lũng Hầu nhắc lại lời từng nói về sào huyệt Hỏa Thiềm thú có nửa nằm trong dung nham, thú có thể nhảy vào hồi phục.","anchor":"Theo Thương Khôn Thượng Nhân nói, sào huyệt Hỏa Thiềm thú cơ hồ có một nửa nằm trong dung nham"},{"importance":"bridge","chuong":"@c0815","mucCt":"gon","text":"Được nhắc là chủ cũ để lại Bích Cưu độc và là nguồn thông tin về sào huyệt cùng đặc tính hồi phục của Hỏa Thiềm thú mà cả nhóm dựa vào để định kế, riêng Hàn Lập giấu hai đồng bạn nguồn gốc này.","anchor":"Bích Cưu độc nguyên là bảo vật của Thương Khôn Thượng Nhân để lại"}]},"nguon":["@c0814","@c0815"]},{"id":"mon-chu-quy-linh-mon","name":"Môn chủ Quỷ Linh Môn","cn":"","aliases":["hắc bào trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Quỷ Linh Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nguyên Anh Sơ Kỳ","trangThai":"song","blurb":"Môn chủ Quỷ Linh Môn, tu vi Nguyên Anh Sơ Kỳ. Dẫn tinh nhuệ tông môn vào Trụy Ma Cốc mưu đoạt Linh Miểu Viên, khẳng định Linh Miểu Viên có thật và Trụy Ma Cốc do Thượng cổ tu sĩ tu kiến để trông coi nơi này.","vaiTro":"Môn chủ Quỷ Linh Môn, chỉ huy chiến dịch chiếm Linh Miểu Viên trong Trụy Ma Cốc","tinhCach":"Tham vọng lớn, tự tin có chứng cớ; quyết đoán dám mang hơn nửa tinh nhuệ tông môn vào hiểm địa; biết dùng lời hứa lợi ích để lung lạc đồng minh","tabs":{"diem":[{"text":"Khẳng định Linh Miểu Viên có thật, Trụy Ma Cốc do Thượng cổ tu sĩ tu kiến chuyên để trông coi nơi này, bổn tông có bảy tám phần nắm chắc và có chứng cớ.","chuong":"@c0822"},{"text":"Hứa nếu thành công, Quỷ Linh Môn trở thành ma đạo đệ nhất đại tông phái và giúp Ngụy Vô Nhai đột phá Hóa Thần Kỳ.","chuong":"@c0822"}],"kinhLich":[{"chuong":"@c0822","importance":"normal","mucCt":"ky","tieuDe":"Tiết lộ chân tướng Trụy Ma Cốc và Linh Miểu Viên","text":"Dẫn Ngụy Vô Nhai, Vương Thiên Cổ cùng bốn đệ tử Kết Đan Kỳ leo lên hắc sơn thạch tiến về Linh Miểu Viên. Khẳng định Linh Miểu Viên có thật, cả Trụy Ma Cốc do Thượng cổ tu sĩ tu kiến chuyên để trông coi Linh Miểu Viên, bổn tông có bảy tám phần nắm chắc. Hứa Quỷ Linh Môn thành ma đạo đệ nhất đại tông phái và giúp Ngụy Vô Nhai đột phá Hóa Thần Kỳ. Thừa nhận Chung trưởng lão đã tách ra tìm bảo vật trân hi ở chỗ bí mật khác trong nội cốc.","anchor":"bổn tông xác thực có bảy tám phần nắm chắc"}],"tuViMoc":[{"chuong":"@c0822","canhGioi":"Nguyên Anh Sơ Kỳ","text":"Được xác nhận tu vi Nguyên Anh Sơ Kỳ.","importance":"major"}],"nhanMach":[{"ten":"Ngụy Vô Nhai","tag":"dong-minh","quanHe":"Mượn danh Ngụy Vô Nhai chấn trụ tu sĩ khác đổi lấy chia bảo vật","ghiChu":"Ngụy Vô Nhai ngoài mặt hợp tác nhưng trong lòng không tin"},{"ten":"Vương Thiên Cổ","tag":"khac","quanHe":"Thuộc hạ đi cùng, phụ trách đệ tử"},{"ten":"Chung trưởng lão","tag":"khac","quanHe":"Trưởng lão dưới quyền, được phái đi tìm bảo vật khác"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0822"]},{"id":"lao-gia-ho-lo","tabs":{"kinhLich":[],"tuiDo":{"phapBao":[{"ten":"Hai thanh phi qua","loai":"pháp bảo","trangThai":"dang-co","moTa":"Hai thanh thương/giáo dùng thay pháp kỳ trước đó, đồng loạt bắn tấn công.","nguon":"@c0816"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0816"]}]};
